window.__SEARCH_INDEX = [{"title":"Comprehensive type casting examples","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_CAST","tags":["cds-view"],"description":"Comprehensive type casting examples. Key topics: CAST converts a value from one data type to another. Syntax: CAST( source_value AS target_type ). Target types ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ CAST converts a value from one data type to another ◆ Syntax: CAST( source_value AS target_type ) ◆ Target types use the abap. namespace: ◆ CAST on amounts should always be followed by ◆ Not all type conversions are valid — incompatible types raise error | CDS Source Code ","detailsText":"┌─────────────────┬────────────────────────────────┐ │ Target Type │ Description │ ├─────────────────┼────────────────────────────────┤ │ abap.dats │ Date (YYYYMMDD) │ │ abap.tims │ Time (HHMMSS) │ │ abap.tstmp │ Timestamp (YYYYMMDDHHMMSS) │ │ abap.char(n) │ Character string of length n │ │ abap.numc(n) │ Numeric text of length n │ │ abap.int2 │ 2-byte integer (INT2) │ │ abap.int4 │ 4-byte integer (INT4) │ │ abap.int8 │ 8-byte integer (INT8) │ │ abap.fltp │ Floating point (FLTP) │ │ abap.dec(n,m) │ Packed decimal with n digits, m decimals │ │ abap.string(n) │ Variable-length string │ └─────────────────┴────────────────────────────────┘ @Semantics.amount.currencyCode annotation"},{"title":"level data manipulation — string, arithmetic, CAST, CASE","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_DATA_MANIP","tags":["cds-views"],"description":"Field-level data manipulation — string, arithmetic, CAST, CASE. Key topics: Fields can be transformed inline without a separate ABAP layer. Supported operations","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Fields can be transformed inline without a separate ABAP layer ◆ Supported operations: ◆ Use field aliases to give computed fields meaningful names ◆ @Semantics annotations on computed fields enable downstream OData/analytics | CDS Source Code ","detailsText":"┌─────────────────┬──────────────────────────────────┐ │ Category │ Examples │ ├─────────────────┼──────────────────────────────────┤ │ Arithmetic │ +, -, *, /, DIVISION, MOD │ │ String │ CONCAT, SUBSTRING, REPLACE, etc. │ │ Conversion │ CAST, COALESCE, NULLIF │ │ Conditional │ CASE ... WHEN ... THEN ... END │ │ Date │ DATS_ADD_DAYS, etc. │ └─────────────────┴──────────────────────────────────┘"},{"title":"CDS Overview & Tooling — ADT setup, package creation, CDS","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_INTRO","tags":["cds-views"],"description":"CDS Overview & Tooling — ADT setup, package creation, CDS. Key topics: ADT (ABAP Development Tools) for Eclipse is mandatory — install. Create or use a transpor","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ ADT (ABAP Development Tools) for Eclipse is mandatory — install ◆ Create or use a transportable package (e.g. ZCDS_PRAC) to hold ◆ Use the New > Data Definition wizard (Ctrl+N) → DDL Source → ◆ The CDS DDL editor provides syntax highlighting, code completion ◆ Activation (Ctrl+F3) creates the ABAP Dictionary SQL view and ◆ Use Data Preview (F8) on the activated CDS view to inspect data ◆ Transports carry the DDL source; the SQL view is generated ◆ The ABAP Flight Reference Scenario (/DMO/) provides demo tables | CDS Source Code ","detailsText":"the ADT plugin and connect to an ABAP system (740 SP08+). all CDS artefacts. choose a package and request a transport. (Ctrl+Space), and annotation proposals. the CDS entity in the system. without writing ABAP code. automatically on target systems after import + activation. (travel, booking, customer, agency) shipped with every AS ABAP. USAGE IN ABAP: DATA lt_travel TYPE STANDARD TABLE OF ZPRAC_CDS_INTRO. SELECT * FROM ZPRAC_CDS_INTRO INTO TABLE @lt_travel UP TO 10 ROWS. cl_demo_output=>display( lt_travel )."},{"title":"Simple CDS View — Basic SELECT from a database table","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_SIMPLE","tags":["cds-view"],"description":"Simple CDS View — Basic SELECT from a database table. Key topics: @AbapCatalog.sqlViewName   → Technical SQL view name visible in SE11. @AbapCatalog.compiler.co","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @AbapCatalog.sqlViewName → Technical SQL view name visible in SE11 ◆ @AbapCatalog.compiler.compareFilter → Optimizes WHERE clause filtering ◆ @AbapCatalog.preserveKey → Preserves key fields as defined ◆ @AccessControl.authorizationCheck → #CHECK / #NOT_REQUIRED / #NOT_ALLOWED ◆ @EndUserText.label → Description text (SE11, ADT) ◆ @Environment.systemField:#CLIENT → Client field mapping for implicit WHERE ◆ @Semantics annotations → Define semantic meaning for fields ◆ define view { entity_name } → CDS entity name used in ABAP/openSQL | Concept Diagram CDS View Syntax — Complete Breakdown @AbapCatalog.sqlViewName: 'ZPRAC_SQL_SIMPLE' -- 1. Annotation block @AbapCatalog.compiler.compareFilter: true -- 2. View metadata @AccessControl.authorizationCheck: #CHECK -- 3. Access control @EndUserText.label: 'Simple Example View' -- 4. UI labeling define view ZPRAC_CDS_SIMPLE -- 5. View definition as select from /dmo/travel -- 6. Data source 1–4 Annotations (Metadata) @AbapCatalog.sqlViewName → SQL view name in HANA @AbapCatalog.compiler.compareFilter → Push filter to source @AccessControl.authorizationCheck → #CHECK / #NOT_REQ / #PRIVILEGED_ONLY @EndUserText.label → Display name in Fiori / ADT @Semantics.amount.currencyCode → Currency reference @Search.searchable: true → Enable search (OData) @Consumption.* / @UI.* → Fiori UI annotations 5–6 View Declaration define view → Keyword declares a CDS view ZPRAC_CDS_SIMPLE → View name (use naming convention) as select from → Source = CDS view or DDIC table /dmo/travel → Fully qualified entity name You can also use: alias (as _Alias) Projection: use define view entity Parameters: (param: type) after view name { -- 7. Field list opens key travel_id as TravelId, -- 8. Key element agency_id as AgencyId, customer_id as CustomerId, total_price as TotalPrice, @Semantics.amount.currencyCode: 'CurrencyCode' -- 9. Field-level annotation booking_fee as BookingFee } -- 10. Field list closes 7–10 Field Selection List 7. { } → Curly braces enclose the selected elements 8. key → Marks primary key (CAN be omitted for views based on other views) 9. as → Alias for the output field name (recommended: CamelCase) 10. Field-level annotations → @Semantics, @UI, @Consumption placed BEFORE the field Extended Syntax — Associations, Joins, Filters, Parameters association [0..1] to /dmo/agency as _Agency on $projection.AgencyId = _Agency.agency_id inner / left outer / right outer / cross join → Join other entities in SELECT where Status = 'A' → Filter condition (can use params: $parameters.param_name) with parameters (p_carrid: /dmo/carrier-carrier_id) → Input parameters before SELECT | CDS Source Code ","detailsText":"USAGE IN ABAP: SELECT * FROM ZPRAC_CDS_SIMPLE INTO TABLE @DATA(lt_travel). SELECT TravelId, AgencyId, TotalPrice FROM ZPRAC_CDS_SIMPLE INTO TABLE @DATA(lt_travel_short) WHERE CustomerId = '000115'. DIAGRAM: assets/diagrams/cds-syntax.svg"},{"title":"Modern CDS View Entity syntax — `define view entity` /","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_VIEW_ENTITY","tags":["cds-views"],"description":"Modern CDS View Entity syntax — `define view entity` /. Key topics: `define view entity` drops the mandatory @AbapCatalog.sqlViewName. `define root view entity`","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ `define view entity` drops the mandatory @AbapCatalog.sqlViewName ◆ `define root view entity` marks the view as a RAP root node, ◆ `define view entity` (non-root) is used for reusable association ◆ All existing CDS annotations (@Semantics, @Analytics, etc.) ◆ View entities integrate natively with RAP BOs, OData V4, and ◆ Using view entities is forward-compatible — SAP recommends this | CDS Source Code ","detailsText":"— the CDS entity name IS the runtime SQL view name. enabling transactional behaviour in OData / Fiori apps. views or composition children. work identically with the view-entity syntax. later EML without wrapper views. syntax for all new developments. COMPARISON — Old vs New Syntax: --- OLD: define view with sqlViewName --- @AbapCatalog.sqlViewName: 'ZPRAC_OLD_SIMPLE' define view ZPRAC_CDS_SIMPLE as select from /dmo/travel { ... } --- NEW: define view entity (no sqlViewName) --- define root view entity ZPRAC_CDS_VIEW_ENTITY as select from /dmo/travel { ... }"},{"title":"CDS View built on top of another CDS view (base view)","phase":1,"phaseName":"Fundamentals","category":"Fundamentals","url":"docs.html#ZPRAC_CDS_VIEW_ON_VIEW","tags":["cds-view"],"description":"CDS View built on top of another CDS view (base view). Key topics: A CDS view can SELECT from another CDS view (not just tables). This is the foundation of the ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ A CDS view can SELECT from another CDS view (not just tables) ◆ This is the foundation of the VDM layering model ◆ Views can be stacked: Table → Basic View → Composite → Consumption ◆ Performance consideration: Each layer adds complexity; the HANA ◆ @Semantics annotations should be applied at each layer as needed | CDS Source Code ","detailsText":"optimizer compiles the chain into one SQL, but very deep stacks can impact readability and maintenance STANDARD BASE VIEW USED: /DMO/I_Travel_D — SAP's standard interface view for Travel data This is a SAP-delivered CDS view under the /DMO/ namespace WHEN TO USE: - Adding business logic on top of existing views - Creating specialized subsets for different consumers (Fiori, Analytics) - Applying different authorization checks at different layers"},{"title":"Analytical CDS Views — Cube, Fact, and Dimension views","phase":10,"phaseName":"Analytics & Security","category":"Analytics & Security","url":"docs.html#ZPRAC_CDS_ANALYTICAL","tags":["cds-views"],"description":"Analytical CDS Views — Cube, Fact, and Dimension views. Key topics: @Analytics.dataCategory classifies a CDS view into one of four. A #CUBE view contains measur","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @Analytics.dataCategory classifies a CDS view into one of four ◆ A #CUBE view contains measures (quantifiable key figures) and ◆ A #DIMENSION view provides master data / attributes (e.g., date, ◆ A #FACT view is a granular, transaction-level view that can feed ◆ @Aggregation.default assigns the aggregation behavior for a ◆ Keyword dimensions (fields used for filtering / grouping) do not ◆ @Analytics.query: #TRUE on a view creates a consumable analytical | Concept Diagram Analytical CDS — Cube · Dimension · Query Analytical CDS Architecture Data Source Layer CDS Basic / Interface Views (I_* or direct DDIC tables) Cube View @Analytics.dataCategory: #CUBE Transactional data (facts) + measures Dimension View @Analytics.dataCategory: #DIMENSION Master data / attributes for grouping &amp; filtering Analytical Projection / Query View @AnalyticsDetails.query = true · Combines cube + dimensions + filters Fiori Analytical List Page / KPI Tile / Analysis for Office OData V4 Analytical Service Key Figures vs Dimensions Key Figures (Measures) @Semantics.amount.currencyCode: 'CurrencyCode' @Semantics.quantity.unitOfMeasure: 'UnitCode' Aggregatable numeric fields: SUM, AVG, MIN, MAX, COUNT Example: TotalPrice, BookingFee, FlightPrice Dimensions (Attributes) @AnalyticsDetails.query.filter: { multiplicity: #TO_MANY } @ObjectModel.text.association: '_Text' Grouping / filtering fields: Drill-down, slice, dice Example: AirlineID, CountryCode, Status Analytical CDS Annotations — Quick Reference @Analytics.dataCategory: #CUBE → View is an analytical cube (facts + dimensions) @Analytics.dataCategory: #DIMENSION → View is a dimension (master data / attributes) @AnalyticsDetails.query: true → Expose as query (combine cube + dim) @AnalyticsDetails.query.maxLength → Max result rows for query (default: 1000) @Semantics.amount.currencyCode / @Semantics.quantity.unitOfMeasure → Unit ref @ObjectModel.text.association → Text association for dimension (language-dependent) | CDS Source Code ","detailsText":"analytical roles: #CUBE, #FACT, #DIMENSION, or #QUERY — each determines how the view is interpreted by analytical engines (SAP Analytics Cloud, Analysis for Office, etc.). dimensions (characteristics); it is the primary data source for analytical queries. Measures must be annotated with @Aggregation.default to define how they are aggregated. product, customer) and is associated to a cube or fact view via CDS associations. It contains no measures. into cubes. The distinction from #CUBE is subtle: a #FACT view typically has no pre-defined aggregations and exposes all transactional detail; a #CUBE is the consumable analytical layer. measure: #SUM, #MIN, #MAX, #COUNT, #AVG, #FORMULA (for calculated measures), or #NONE (for dimensions / non-aggregatable fields). get @Aggregation.default; they are implicitly grouped-on in SQL. Association to dimension views is the recommended pattern for enriching cube data with text / attributes. query that can be exposed via InA / OData for reporting tools. In modern S/4HANA, provider contract analytical_query is the preferred successor (see ZPRAC_CDS_ANALYTICAL_V3). COMPARISON TABLE: Cube vs Fact vs Dimension vs Query Feature | #CUBE | #FACT | #DIMENSION | #QUERY ----------------|------------------|-------------------|----------------|----------------------- Measures | Yes | Yes | No | Yes (restricted) Aggregation | Always defined | Optional | N/A | Inherited / overridden Associations | To dimensions | To dimensions | To other dims | Based on cube/dim Consumption | Analytics tools | Cubes / queries | Cubes, facts | End-user reporting Text support | Via association | Via association | Native | Via association S/4HANA 2025+ | Supported | Supported | Supported | Legacy (use V3) Example use | Sales cube | Sales line items | Product / Date | Quarterly sales report SOURCE CODE: Dimension View DIAGRAM: assets/diagrams/analytical-cds.svg"},{"title":"CDS Analytical Projection Views (V3) — Modern analytical","phase":10,"phaseName":"Analytics & Security","category":"Analytics & Security","url":"docs.html#ZPRAC_CDS_ANALYTICAL_V3","tags":["cds-views"],"description":"CDS Analytical Projection Views (V3) — Modern analytical. Key topics: V3 analytical queries use define view entity as projection on. A V3 analytical projection ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ V3 analytical queries use define view entity as projection on ◆ A V3 analytical projection MUST be built on a cube view ◆ Consumption happens exclusively via the InA (Information Access) ◆ Restricted measures use @Aggregation.default: #FORMULA combined ◆ Calculated quantities are annotated with @Semantics.quantity ◆ Compared to legacy @Analytics.query, V3 provides stronger | CDS Source Code ","detailsText":"with the provider contract analytical_query clause (kernel 7.83+) — they replace the older @Analytics.query: #TRUE approach. (@Analytics.dataCategory: #CUBE); the underlying cube provides the measures and dimensions that the projection selects. protocol — direct SQL reading or Open SQL FROM is NOT allowed. Tools: SAP Analytics Cloud, Analysis for Office, custom InA consumers. with the expression element syntax to define calculated key figures (e.g., ratio, profit margin, year-over-year change). and @Semantics.quantity.unitOfMeasure to ensure correct unit handling across aggregation boundaries. compile-time checks (e.g., verifying that only measures from the cube are exposed, proper aggregation definitions, and correct InA metadata generation). COMPARISON: Legacy Analytical Query vs V3 Analytical Projection View Feature | Legacy @Analytics.query | V3 analytical_query projection ---------------------|------------------------------|---------------------------------- Syntax | define view + annotation | define view entity as projection on Provider contract | None (implicit) | provider contract analytical_query Base object | Any CDS view or cube | Must be a cube view (#CUBE) SQL access allowed? | Yes | No (InA protocol only) Measure restriction | Manual filtering | #FORMULA + expression syntax Compile-time checks | Minimal | Strict (measures, aggregations, InA) Transport layer | Standard CDS transport | Standard CDS transport SAP Analytics Cloud | Yes (via InA/OData) | Yes (native InA) ADT support | Code completion limited | Full syntax check in ADT Future-proofing | Deprecated (still supported) | Recommended for new development SOURCE CODE: V3 Analytical Projection View"},{"title":"level access based on user authorization","phase":10,"phaseName":"Analytics & Security","category":"Analytics & Security","url":"docs.html#ZPRAC_CDS_DCL","tags":["cds-views"],"description":"Restrict row-level access based on user authorization. Key topics: DCL is a SEPARATE artifact from the CDS view — file extension .asr. The CDS view must have @A","sections":["Key Learning Points","Concept Diagram"],"sectionsText":"Key Learning Points ◆ DCL is a SEPARATE artifact from the CDS view — file extension .asr ◆ The CDS view must have @AccessControl.authorizationCheck: #CHECK ◆ DCL uses ASPECT = PVZM to define mapping between fields and auth objects ◆ Implicit access control is based on PFCG authorization object fields ◆ DCL can restrict: SELECT, INSERT, UPDATE, DELETE (per operation) | Concept Diagram DCL — Access Control Flow 1. User Request SAP User / OData via Fiori or API 2. CDS View Accessed CDS View Entity @AccessControl.authorizationCheck 3. DCL Security Check DCL: define role PFCG → aspect mapping Access Granted? Data Returned Row-filtered set No Data / Suppressed DCL: define role Syntax @MappingRole: true @MappingRoleName: 'ZPRAC_TRAVEL_SALES' define role ZPRAC_TRAVEL_SALES { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( org_value, 'S_CARRID', 'ACTVT' ); } How DCL Works 1. User accesses a CDS view via OData / SE16 2. CDS annotation @AccessControl.authorizationCheck: #CHECK 3. DCL role is evaluated at runtime 4. PFCG authorization object is checked 5. If match → row is visible; otherwise → hidden S_CARRID = Authorization object for airline ACTVT = Activity (03=display, 02=change, 01=create) @AccessControl.authorizationCheck — 3 Modes #CHECK Default. DCL role is checked. If no DCL exists → no data returned. Use for most production views. #NOT_REQUIRED DCL role is NOT checked. All users see all rows. Use for tech / utility views only. #PRIVILEGED_ONLY Only DCL-defined users pass. Restrictive — no default access. Use for sensitive / financial data. PFCG Authorization → DCL Mapping Pipeline PFCG Role SAP Role assignment Auth Object S_CARRID, ACTVT DCL: aspect pfcg_auth() mapping CDS Row Filter WHERE clause injected Data","detailsText":"WHAT IS DCL? DCL (Data Control Language) is a CDS artifact (.asr file) that defines row-level security for CDS views. It works with PFCG authorization objects to filter data per user. DCL SYNTAX OVERVIEW: @EndUserText.label: 'Access control for ZPRAC_CDS_SIMPLE' @MappingRole: true define role ZPRAC_CDS_SIMPLE_AC { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '03', AGENCY = $sy_user_agr() ); } COMMON DCL PATTERNS: ┌──────────────────────────────────┬────────────────────────────────┐ │ Pattern │ When to use │ ├──────────────────────────────────┼────────────────────────────────┤ │ grant select ... where ... │ Standard row-level restriction │ │ grant all on ... │ Full access (admin purpose) │ │ inherit access for ... │ Delegate to underlying view │ │ aspect pfcg_auth(...) │ Map CDS field to PFCG auth obj │ │ $sy_user_agr() │ User's authorization values │ └──────────────────────────────────┴────────────────────────────────┘ ADVANCED DCL — INHERIT ACCESS: Delegate access control to an underlying view. The current view inherits the DCL restrictions from its data source automatically. @EndUserText.label: 'DCL for ZPRAC_CDS_VIEW_ON_VIEW (inherits)' @MappingRole: true define role ZPRAC_CDS_VON_V_AC { grant select on ZPRAC_CDS_VIEW_ON_VIEW { grant inherited access for select on ZPRAC_CDS_SIMPLE; } } ADVANCED DCL — DEFINE ASPECT: Create reusable authorization conditions for multiple roles. @EndUserText.label: 'Aspect for Agency authorization' define aspect ZPRAC_ASPECT_AGENCY { pfcg_auth( /DMO/TRV, ACTVT = '03', AGENCY = $sy_user_agr() ) } define role ZPRAC_CDS_SIMPLE_AC { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect ZPRAC_ASPECT_AGENCY; } ADVANCED DCL — CONDITIONAL GRANTS: Grant different access levels based on user authorization values. define role ZPRAC_CDS_TRAVEL_AC { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '03', AGENCY = $sy_user_agr() ); grant insert, update, delete on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '01,02', AGENCY = $sy_user_agr() ); } ADVANCED DCL — INSTANCE-BASED ACCESS: Restrict access to specific instances based on field values. Multiple WHERE conditions can be combined with AND/OR. define role ZPRAC_CDS_SIMPLE_AC { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '03', AGENCY = $sy_user_agr() ) and (Status) = aspect pfcg_auth( /DMO/TRV_STATUS, ACTVT = '03', STATUS = $sy_user_agr() ); } ADVANCED DCL — ACCESS POLICIES FOR READ/WRITE: Use different PFCG activities for read vs write access. define role ZPRAC_CDS_SIMPLE_AC { grant select on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '03', AGENCY = $sy_user_agr() ); grant insert on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '01', AGENCY = $sy_user_agr() ); grant update on ZPRAC_CDS_SIMPLE where (AgencyId) = aspect pfcg_auth( /DMO/TRV, ACTVT = '02', AGENCY = $sy_user_agr() ); } BEST PRACTICE RULES: ┌────────────────────────────────────────────────┬────────────────────────────┐ │ Rule │ Reason │ ├────────────────────────────────────────────────┼────────────────────────────┤ │ Always use @AccessControl.authorizationCheck │ Required for DCL to apply │ │ Use #CHECK at consumption layer │ Enforces row-level security│ │ Use inherit access for VDM layer stacking │ Avoids DCL duplication │ │ Use define aspect for reusable conditions │ DRY principle │ │ Grant different activities per operation │ Principle of least privilege│ │ Never use DCL on private/interface views │ Internal views don't need it│ │ Always run unit tests with DISABLE_DCL │ Avoid flaky tests │ └────────────────────────────────────────────────┴────────────────────────────┘ DIAGRAM: assets/diagrams/dcl-flow.svg"},{"title":"CDS Release Contracts & API Stability — C0, C1, C2, C3","phase":10,"phaseName":"Analytics & Security","category":"Analytics & Security","url":"docs.html#ZPRAC_CDS_RELEASE_CONTRACTS","tags":["cds-views"],"description":"CDS Release Contracts & API Stability — C0, C1, C2, C3. Key topics: Release contracts govern the stability and allowed consumption. C0 (Extension Contract) — th","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Release contracts govern the stability and allowed consumption ◆ C0 (Extension Contract) — the view is released for customer ◆ C1 (System-internal Use / API Contract) — the view is a stable ◆ C2 (Remote Consumption / Remote Contract) — the view is ◆ C3 (Configuration / Configuration Contract) — the view is ◆ @AbapCatalog.interface.releaseState can be #RELEASED_FOR_CUSTOMER ◆ Visual indicators in ADT (green / yellow / red icons) show the | CDS Source Code ","detailsText":"scope of a released CDS view. They are defined via @AbapCatalog.interface on the view, ensuring that consumers can rely on the interface without unexpected breaking changes. extensibility. Customers can append fields via CDS extension includes. The contract guarantees that the extension points remain stable across upgrades. API for system-internal consumption. Other views or ABAP code can depend on it. The interface is frozen; changes require deprecation cycles. released for remote access (OData, RFC, HTTP). The structure and semantics are guaranteed for external-facing services. Stronger stability guarantees than C1. released for managed configuration content. Typically used for customizing / configuration tables exposed through CDS. Changes are possible but communicated. (visible to customers) or #RELEASED_FOR_CUSTOMER_C0 etc. to set a specific contract. In ADT, the System Library view shows the release contract and state for each released CDS artifact. release status. Released views are protected against incompatible changes during upgrade; contract violations are flagged by the syntax checker and can block transport. COMPARISON TABLE: C0 — C3 Release Contracts Contract | Name | Use Case | Stability | Consumer Scope ---------|------------------------|------------------------------|-----------|------------------------------ C0 | Extension Contract | Customer extensions | High | Customers (extend fields) C1 | API Contract | System-internal API | Very High | Internal views / ABAP C2 | Remote Contract | OData / RFC / HTTP services | Highest | Remote / external systems C3 | Configuration Contract | Configuration / customizing | Medium | Managed content consumers EXAMPLE: Releasing a CDS View with Extension Contract (C0)"},{"title":"AMDP with dynamic WHERE clause via APPLY_FILTER","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZCL_AMDP_DYNAMIC","tags":["table-functions"],"description":"AMDP with dynamic WHERE clause via APPLY_FILTER. Key topics: APPLY_FILTER applies a WHERE condition dynamically at runtime. The filter is a string passed from A","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ APPLY_FILTER applies a WHERE condition dynamically at runtime ◆ The filter is a string passed from ABAP (e.g. \"TRAVELID = '00000009'\") ◆ APPLY_FILTER can work on a CDS view directly OR on a temp table ◆ cl_shdb_seltab=>combine_seltabs converts ABAP RANGES to SQL WHERE string ◆ The filter string uses HANA SQL syntax (field names in UPPERCASE) | CDS Source Code ","detailsText":"USAGE IN ABAP REPORT: DATA lv_travel_id TYPE /dmo/travel_id. SELECT-OPTIONS: s_travel_id FOR lv_travel_id. \" Convert ABAP SELECT-OPTIONS to a WHERE clause string DATA(lv_where) = cl_shdb_seltab=>combine_seltabs( it_named_seltabs = VALUE #( ( name = 'TRAVELID' dref = REF #( s_travel_id[] ) ) ) ). zcl_amdp_dynamic=>get_details( EXPORTING im_select_op = lv_where IMPORTING ex_travel_details = DATA(lt_travel) )."},{"title":"AMDP with a simple input parameter — fetch travel by ID","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZCL_AMDP_SIMPLE","tags":["cds-view","vdm","table-functions"],"description":"AMDP with a simple input parameter — fetch travel by ID. Key topics: Class must implement IF_AMDP_MARKER_HDB. Method must be static (CLASS-METHODS). Parameters ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Class must implement IF_AMDP_MARKER_HDB ◆ Method must be static (CLASS-METHODS) ◆ Parameters passed by VALUE (IMPORTING VALUE(...)) ◆ USING clause declares external CDS/tables accessible in SQLScript ◆ OPTIONS READ-ONLY for query-only procedures | CDS Source Code ","detailsText":"WHAT IS AN AMDP? AMDP allows writing HANA database procedures directly in ABAP classes. Benefits over native CDS: ✓ Complex procedural logic (LOOPs, IF/ELSE, temp tables) ✓ Dynamic SQL via APPLY_FILTER ✓ Multiple result sets (when using PROCEDURE, not FUNCTION) ✓ HANA-specific features (PAL, SERIES, etc.) AMDP TYPES: BY DATABASE FUNCTION → Single result set (used by Table Functions) BY DATABASE PROCEDURE → Multiple result sets (called from ABAP reports) USAGE IN ABAP REPORT: \" Call via class name (static) zcl_amdp_simple=>get_details( EXPORTING im_travel_id = '00000014' IMPORTING ex_travel_details = DATA(lt_travel_1) ). \" Call via object instance DATA(lo_amdp) = NEW zcl_amdp_simple( ). lo_amdp->get_details( EXPORTING im_travel_id = '00000009' IMPORTING ex_travel_details = DATA(lt_travel_2) )."},{"title":"Table Function with currency amount semantics and CAST","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZPRAC_CDS_TF_CURRENCY","tags":["cds-views"],"description":"Table Function with currency amount semantics and CAST","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":""},{"title":"Advanced Table Function — DUMMY table, IF/ELSE, variables","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZPRAC_CDS_TF_DUMMY","tags":["cds-views"],"description":"Advanced Table Function — DUMMY table, IF/ELSE, variables. Key topics: DUMMY table: HANA system table with exactly 1 row, used for. Local variables: DECLARE var","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ DUMMY table: HANA system table with exactly 1 row, used for ◆ Local variables: DECLARE var_name type; inside SQLScript ◆ IF/ELSE logic is possible inside the AMDP method (NOT in pure CDS) ◆ INTO clause stores single-row SELECT results into variables ◆ CASE can also be used inside SQLScript (not just CDS) ◆ Date formatting with TO_DATE / TO_CHAR in HANA SQLScript | CDS Source Code ","detailsText":"fetching system values (CURRENT_DATE, USER(), etc.) into vars"},{"title":"CDS View consuming a parameterized Table Function","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZPRAC_CDS_TF_PARAM","tags":["parameters"],"description":"CDS View consuming a parameterized Table Function. Key topics: Table function parameters are defined WITH PARAMETERS. Return structure includes only output colu","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Table function parameters are defined WITH PARAMETERS ◆ Return structure includes only output columns (not params) ◆ Pass constants via: TF_NAME( param1: 'value1', param2: 'value2' ) ◆ Pass CDS parameters via: TF_NAME( param1: $parameters.p1 ) ◆ Parameters in SQLScript are referenced with :param_name | CDS Source Code ","detailsText":""},{"title":"CDS View consuming a simple Table Function","phase":11,"phaseName":"Table Functions & AMDP","category":"Table Functions & AMDP","url":"docs.html#ZPRAC_CDS_TF_SIMPLE","tags":["cds-view","vdm"],"description":"CDS View consuming a simple Table Function","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":"WHAT IS A TABLE FUNCTION? A Table Function is a CDS artifact that delegates the SQL logic to an AMDP method (HANA SQLScript). This allows: ✓ Complex procedural logic (loops, IF/ELSE, temp tables) ✓ HANA-specific features (Fuzzy Search, PAL, etc.) ✓ SQLScript advanced constructs not possible in CDS KEY POINTS: 1. Parameters are optional (none here — simple case) 2. Always needs a RETURN parameter (structure of output columns) 3. Requires an AMDP class with IF_AMDP_MARKER_HDB interface 4. Static method with BY DATABASE FUNCTION FOR HDB LANGUAGE SQLSCRIPT 5. No extra annotations needed in the consuming CDS view 6. Table functions support JOINs, UNIONs like regular CDS views 7. Multiple CDS views can consume the same table function"},{"title":"CDS in ABAP Cloud & Clean Core Strategy — Modern","phase":12,"phaseName":"Quality, Performance & Enterprise","category":"Quality, Performance & Enterprise","url":"docs.html#ZPRAC_CDS_CLOUD_CORE","tags":["rap","cloud-core"],"description":"CDS in ABAP Cloud & Clean Core Strategy — Modern. Key topics: ABAP Cloud development model requires `#CLOUD_DEVELOPMENT` as. Released APIs are marked with `@ABA","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ ABAP Cloud development model requires `#CLOUD_DEVELOPMENT` as ◆ Released APIs are marked with `@ABAP.ReleaseState: #RELEASED` ◆ Clean-core extensibility: SAP's standard namespace (/DMO/, /SAP/) ◆ Cloud vs on-premise differences: `define view entity` is ◆ Extensibility via `@EndUserText.label: 'Custom'` and ◆ CDS view extensions (`extends view`) add fields from customer ◆ Use ADT's system library (Object Explorer > Properties) to ◆ Upgrade-safe custom code means using only released APIs, | CDS Source Code ","detailsText":"the language version — only released APIs are allowed. The compiler enforces this at compile time. in the system library (ADT). Using unreleased objects causes a syntax error in cloud projects. is locked. Extensions go into customer namespace (Z*, Y*) via CDS appends, custom fields, custom logic, and RAP BO extensions. mandatory in cloud (DDIC-based `define view` is not allowed); no direct RFC/BAPI calls; no ABAP SQL in OPEN SQL that bypasses CDS; `@AbapCatalog.sqlViewName` is deprecated. `@Extensible: true` on CDS views allows customers to append fields without modifying the original view. tables or custom logic without changing standard CDS — key ingredient of the \"clean-core\" approach. verify the release state of any API before using it. extending via enhancement options, and never modifying SAP objects. SAP guarantees backward compatibility of released APIs. COMPARISON TABLE: ON-PREMISE CDS vs ABAP CLOUD CDS Aspect On-Premise CDS ABAP Cloud CDS ----------------------- --------------------------- --------------------------- Language version Standard ABAP (#STANDARD) #CLOUD_DEVELOPMENT View definition define view (deprecated) define root view entity DDIC compatibility CDS DDIC-based views No DDIC view dependency SQL View name @AbapCatalog.sqlViewName Deprecated — use entity name API usage Any API Only @ABAP.ReleaseState: #RELEASED DB hints Allowed Not allowed in cloud Modifications Can modify SAP objects Never modify — extend only Extensibility SAP Notes, corrections Key-user / developer appends Deployment On-prem S/4, BW, etc S/4HANA Cloud, BTP ABAP Transport mechanism CTS (file-based) gCTS / abapGit / ADT-managed RFC/BAPI Allowed Not allowed (use RAP / OData) Authorization DCL + SU22 DCL + IAM apps Buffer behavior Full buffer control @AccessControl.authorizationCheck Upgrade protection Manual regression Automatic — released API contracts 1. CDS VIEW EXTENSION — ADDITIVE EXTENSIBILITY"},{"title":"CDS Performance Optimization — Query planning, buffering,","phase":12,"phaseName":"Quality, Performance & Enterprise","category":"Quality, Performance & Enterprise","url":"docs.html#ZPRAC_CDS_PERFORMANCE","tags":["cds-views"],"description":"CDS Performance Optimization — Query planning, buffering,. Key topics: @AbapCatalog.compiler.compareFilter: true enables filter push-down. Push-down principle: ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @AbapCatalog.compiler.compareFilter: true enables filter push-down ◆ Push-down principle: compute aggregation, filtering, and projection ◆ Nested views inflate query plans exponentially — the SQL merger ◆ @AbortCatalog.preserveKey prevents the compiler from removing ◆ Parameterized views (@ParameterSystem) enable partition pruning. ◆ Index coverage is critical for large tables — ensure secondary ◆ The N+1 anti-pattern occurs when associations are evaluated lazily ◆ Decision guide: CDS is declarative — use it for data retrieval and | CDS Source Code ","detailsText":"to HANA for WHERE conditions matching view parameters — without it, filters are applied on the application server after all data arrives. in HANA, never on the ABAP application server. A CDS view is a declarative SQL specification; the ABAP compiler decides the execution location — annotations guide that decision. flattens up to ~300 levels, but each nesting adds plan complexity. Prefer CDS view entities over deprecated CDS DDIC-based views. key fields during SQL merger — essential when keys are needed by the consumer (e.g., OData) but pruned as unused by the planner. Pass filter values as parameters so HANA eliminates irrelevant partitions before scanning. indexes exist for SELECT fields used in WHERE and JOIN conditions. Check HANA PlanViz for full-table scans. in a loop. Use @Environment.systemField or explicit JOIN to materialize associations in a single query. simple calculations. Use AMDP (ABAP Managed Database Procedures) for imperative logic, complex transformations, or when you need database-procedure features unavailable in CDS. BEFORE/AFTER COMPARISON -------------------------------------------------------------------- BEFORE — Poorly written view (SELECT *, no filter push-down) -------------------------------------------------------------------- define view ZPRAC_TRAVEL_BEFORE as select from /dmo/travel { * } // SELECT * pulls all columns into app server memory // No compareFilter → WHERE is applied in ABAP, not HANA // No parameterization → full table scan on every call -------------------------------------------------------------------- AFTER — Optimized view with compareFilter, parameters, explicit fields -------------------------------------------------------------------- define root view entity ZPRAC_TRAVEL_AFTER as select from /dmo/travel composition [0..*] of /dmo/booking as _Booking on $projection.travel_id = _Booking.travel_id { key travel_id, agency_id, customer_id, @Semantics.amount.currencyCode: 'currency_code' total_price, currency_code, status, created_by, created_at } OPTIMIZED CDS VIEW — PRODUCTION-READY"},{"title":"driven","phase":12,"phaseName":"Quality, Performance & Enterprise","category":"Quality, Performance & Enterprise","url":"docs.html#ZPRAC_CDS_RAP_EVENTING","tags":["rap-eventing"],"description":"RAP Business Events & Enterprise Eventing — Event-driven. Key topics: Define events in the behavior definition (BDEF) with. `RAISE ENTITY EVENT FROM` in the beh","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Define events in the behavior definition (BDEF) with ◆ `RAISE ENTITY EVENT FROM` in the behavior pool (ABAP class) ◆ Event binding maps a RAP business event to a topic in SAP Event ◆ Derived events use a CDS view as the event payload, enabling ◆ Local event handlers use CL_ABAP_BEHAVIOR_EVENT_HANDLER as ◆ SAP Event Mesh integration: the RAP event is published to an ◆ 0 or HTTP webhooks. Configure QoS 0/1 as needed. ◆ Monitor events via /IWXBE/MONITOR and /IWXBE/LOG — track | CDS Source Code ","detailsText":"`define event` — each event carries a typed parameter structure (CDS abstract entity) that defines the payload contract. fires the event during the save sequence (FOR SAVE, FOR MODIFY). The event is queued and delivered asynchronously after COMMIT. Mesh via the /IWXBE framework — configured in transaction /IWXBE/CONFIG or via the `generate event binding` ADT wizard. custom projections and filtering before the event reaches subscribers — e.g. only emit events for status = 'B'. the base class. Implement IF_ABAP_BEHAVIOR_EVENT_HANDLER~ON_ to react to events within the same system. Event Mesh queue/topic; external consumers subscribe via AMQP event status (CREATED, PUBLISHED, ERROR) and payload content for debugging. FLOW DIAGRAM — CDS → RAP BO → Event → Event Mesh → Consumer +------------+ +-----------+ +----------+ +------------+ | CDS View | --> | RAP BO | --> | Event | --> | SAP Event | | (Data def) | | (Behavior)| | (Rise) | | Mesh | +------------+ +-----------+ +----------+ +------------+ | | | | define view behavior RAISE Topic/ entity /dmo/ definition ENTITY Queue travel for EVENT (AMQP) Travel { event TravelCreated param ...; } | | | | v v v v +------------+ +-----------+ +----------+ +------------+ | Derived | | Behavior | | Event | | Consumer | | Event View | | Pool | | Binding | | (Ext. Sys)| | (CDS) | | (ABAP | | (/IWXBE) | | Webhook / | | | | Class) | | | | AMQP | +------------+ +-----------+ +----------+ +------------+ Flow steps: 1. CDS view provides data model. 2. RAP BO processes business logic (MODIFY, SAVE). 3. Behavior pool raises entity event on state change. 4. Event binding maps event to Event Mesh topic. 5. Event Mesh delivers message to external consumer. BEHAVIOR DEFINITION (BDEF)"},{"title":"CDS Unit Testing with Test Double Framework — Isolated","phase":12,"phaseName":"Quality, Performance & Enterprise","category":"Quality, Performance & Enterprise","url":"docs.html#ZPRAC_CDS_UNIT_TEST","tags":["cds-views"],"description":"CDS Unit Testing with Test Double Framework — Isolated. Key topics: CL_CDS_TEST_ENVIRONMENT=>CREATE() creates a test double. GET_DOUBLE()->INSERT() injects test","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ CL_CDS_TEST_ENVIRONMENT=>CREATE() creates a test double ◆ GET_DOUBLE()->INSERT() injects test data into the double tables ◆ Wrap tests in an ABAP Unit class (CLASS ... FOR TESTING) with ◆ DISABLE_DCL (via CL_CDS_TEST_ENVIRONMENT=>GET_DCL()) bypasses ◆ Test WHERE clause filtering, CASE and COALESCE expressions, and ◆ Integrate with ATC (ABAP Test Cockpit) — CDS unit tests are ◆ CI/CD pipeline integration: execute via RUN_ATC or CL_ATC_API. | CDS Source Code ","detailsText":"environment that replaces the underlying dictionary tables of a CDS view with in-memory test data — no real database access. before the CDS SELECT executes. Data lifetime is scoped to the test method / class. SETUP and TEARDOWN methods. TEARDOWN must call DESTROY() to release the environment. DCL / DCLX (access control) during tests — crucial for isolating view logic from authorization rules. calculated fields. These contain business logic prone to error. discovered and executed automatically when configured in the test class as FOR TESTING. Gate the build on CDS test results. TIPS — WHAT TO TEST: ✓ Calculated fields (CASE, COALESCE, aggregation) ✓ WHERE clause correctness (boundary values, NULL handling) ✓ Associations that project fields into the result ✓ Currency/unit conversion logic ✓ @Consumption annotations that affect client behavior TIPS — WHAT NOT TO TEST: ✗ Simple 1:1 projections from a single table (pure pass-through) ✗ Pure annotation changes (annotations do not alter result rows) ✗ Database-internal optimizations (compareFilter, merge behavior) ✗ DCL / authorization (test those via SAML / authorization unit tests) ABAP UNIT TEST CLASS — CDS VIEW TEST DOUBLE"},{"title":"CDS View parameters with DEFAULT values (optional params)","phase":2,"phaseName":"Parameters & Filtering","category":"Parameters & Filtering","url":"docs.html#ZPRAC_CDS_DEFAULT_PARAM","tags":["parameters"],"description":"CDS View parameters with DEFAULT values (optional params). Key topics: Parameters become OPTIONAL when they have a DEFAULT value. If caller omits the parameter,","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Parameters become OPTIONAL when they have a DEFAULT value ◆ If caller omits the parameter, the DEFAULT is used ◆ DEFAULT values can be: ◆ All parameters with defaults are optional — mix of optional ◆ A view can have ONLY optional params (all with defaults) ◆ @Semantics annotations on fields enable OData/Analytics consumption | CDS Source Code ","detailsText":"- Literal strings (must match target type) - Numeric literals - Date literals (YYYYMMDD) - $session.system_date (dynamic default!) and mandatory parameters is allowed USAGE IN ABAP: \" With all parameters (override defaults) SELECT * FROM ZPRAC_CDS_DEFAULT_PARAM( p_currency = 'EUR', p_max_price = '5000' ) INTO TABLE @DATA(lt_travel1). \" Without parameters (all defaults applied) SELECT * FROM ZPRAC_CDS_DEFAULT_PARAM( ) INTO TABLE @DATA(lt_travel2). --> Equivalent to: currency_code = 'USD' AND max_price = 99999999"},{"title":"CDS View with input parameters — filter at query time","phase":2,"phaseName":"Parameters & Filtering","category":"Parameters & Filtering","url":"docs.html#ZPRAC_CDS_PARAM","tags":["parameters"],"description":"CDS View with input parameters — filter at query time. Key topics: Input parameters defined in WITH PARAMETERS block. Parameters typed using existing data eleme","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Input parameters defined in WITH PARAMETERS block ◆ Parameters typed using existing data elements (e.g. /dmo/travel_id) ◆ Parameters referenced via :param_name in WHERE clause ◆ No extra annotations needed — consumed in ABAP via explicit param passing ◆ Parameters are mandatory by default (use DEFAULT to make optional) ◆ @Semantics annotations are essential for downstream consumption | CDS Source Code ","detailsText":"even on parameterized views (Fiori, Analytics, OData) USAGE IN ABAP: SELECT * FROM ZPRAC_CDS_PARAM( p1_travel_id = @p_travel, p2_agency_id = @p_agency ) INTO TABLE @DATA(lt_travel). DATA: p_travel TYPE /dmo/travel_id VALUE '00000009', p_agency TYPE /dmo/agency_id VALUE '070032'."},{"title":"Passing constants to a parameterized CDS view","phase":2,"phaseName":"Parameters & Filtering","category":"Parameters & Filtering","url":"docs.html#ZPRAC_CDS_PARAM_CONST","tags":["parameters"],"description":"Passing constants to a parameterized CDS view. Key topics: A non-parameterized view can consume a parameterized view. Syntax: view_name( param1: 'value1', param","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ A non-parameterized view can consume a parameterized view ◆ Syntax: view_name( param1: 'value1', param2: 'value2' ) ◆ This is useful for creating pre-filtered views (e.g. by agency) ◆ Alternative: pass $parameters.variable to forward ABAP params ◆ @Semantics annotations must be re-declared at each view layer | CDS Source Code ","detailsText":"by passing constant values for the parameters for proper downstream consumption (OData, Analytics) WHEN TO USE: - Creating a fixed-reporting view filtered by specific criteria - Creating a layer of pre-filtered abstractions on parameterized views - Testing with hardcoded test data during development"},{"title":"Forwarding ABAP parameters to another parameterized CDS view","phase":2,"phaseName":"Parameters & Filtering","category":"Parameters & Filtering","url":"docs.html#ZPRAC_CDS_PARAM_VAR","tags":["parameters"],"description":"Forwarding ABAP parameters to another parameterized CDS view. Key topics: $parameters.<param_name> → References the current view's input params. Used to forward","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ $parameters. → References the current view's input params ◆ Used to forward parameters to the underlying CDS view/tf ◆ The downstream view's parameter types must match ◆ This creates a transparent parameter chain: ABAP → View A → View B ◆ @Semantics annotations must be maintained at each layer | CDS Source Code ","detailsText":"FLOW: ABAP Report → ZPRAC_CDS_PARAM_VAR(p1: 'X', p2: 'Y') ↓ ZPRAC_CDS_PARAM(p1_travel_id: 'X', p2_agency_id: 'Y') ↓ /dmo/travel (database table) KEYWORD SYNTAX: Parameter mapping uses NAMED notation: downstream_view( param1: $parameters.my_param1, ... )"},{"title":"demand join relationship","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_ASSOCIATION","tags":["associations"],"description":"CDS Association — lazy/on-demand join relationship. Key topics: Association is a DECLARED relationship — NOT executed as a join. Data is fetched lazily (on dema","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Association is a DECLARED relationship — NOT executed as a join ◆ Data is fetched lazily (on demand) when the association is accessed ◆ Cardinality: [1] → exactly one, [0..1] → zero or one, [*] → many ◆ To expose the association publicly, include it in the SELECT list ◆ Consumption via path expression: _Assoc._Customer.FirstName ◆ Associations can be accessed in WHERE clause - implicit join | Concept Diagram Association vs Composition in CDS Association (read-only link) define view ZV_Travel as select from /dmo/travel association [0..1] to /dmo/agency as _Agency on $projection.AgencyId = _Agency.agency_id { key travel_id, agency_id, _Agency.name } Travel (Root) Own identity &amp; persistence reads Agency (Target) Exists independently Cardinality: [0..1] Zero or one · [1] Exactly one · [*] Many Path expression: $projection.AssocName.field → automatic JOIN ✅ Read-only — use in SELECT or path expression ✅ Target is independent — can exist without the source ✅ Lazy-loaded — no JOIN unless path expression is used Composition (parent-child) define root view entity ZV_TravelRoot as select from /dmo/travel composition [0..*] of /dmo/booking as _Booking on $projection.TravelId = _Booking.travel_id { key travel_id, _Booking.* } Travel (Root Entity) Owns children — cannot exist without root Booking (Child) Root UUID is part of child key Cardinality: [0..*] Zero or many · [0..1] Zero or one · [1..*] At least one ✅ Parent-child — child has dependent lifecycle ✅ Child cannot exist without parent (root UUID in key) Association vs Composition — Comparison Table Aspect Association Composition Relationship Read-only reference Parent-child (whole-part) Target Lifecycle Independent (can exist alone) Dependent (dies with parent) Cardinality [0..1], [1], [*] [0..*], [0..1], [1..*] Key Inheritance No (separate keys) Root UUID in child key Loading Lazy (via path expression) Eager (part of parent) Use in SELECT Path expression: _Assoc.field Cannot be selected directly RAP Behavior Read-only (no create/update) Create/update/delete via parent Example Travel → Agency (lookup) Travel → Booking (items) Associations = loose coupling · Compositions = tight coupling with lifecycle management | CDS Source Code ","detailsText":"ASSOCIATION vs JOIN: ┌─────────────┬──────────────────────┬───────────────────┐ │ Aspect │ JOIN │ Association │ ├─────────────┼──────────────────────┼───────────────────┤ │ Fetch │ Eager (always runs) │ Lazy (on-access) │ │ SQL │ Generated upfront │ Dynamic SQL │ │ Performance │ Good for small sets │ Good for optional │ │ Reuse │ Coupled │ Decoupled │ └─────────────┴──────────────────────┴───────────────────┘ CONSUMPTION IN ABAP: SELECT BookingUUID, _Customer.FirstName, _Customer.LastName FROM ZPRAC_CDS_ASSOCIATION INTO TABLE @DATA(lt_bookings). --> The _Customer association is resolved automatically by the framework DIAGRAM: assets/diagrams/assoc-vs-composition.svg"},{"title":"CROSS JOIN — Cartesian product between two tables","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_CROSS_JOIN","tags":["cds-views"],"description":"CROSS JOIN — Cartesian product between two tables. Key topics: CROSS JOIN creates a Cartesian product: |A| × |B| rows. No join condition — every row from A matc","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ CROSS JOIN creates a Cartesian product: |A| × |B| rows ◆ No join condition — every row from A matches every row from B ◆ Can be INNER CROSS JOIN, LEFT CROSS JOIN, or just CROSS JOIN ◆ Use with CAUTION: can generate huge result sets ◆ Common use cases: ◆ HANA optimizes CROSS JOINs but large tables will be slow | Concept Diagram CDS Join Types — Detailed Visual Guide INNER JOIN Table A Table B ON match Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 &lt;-- no match in B Table B (RIGHT): /dmo/agency agency_id | agency_name 1002 | Happy Travel 1003 | Global Tours RESULT: Only rows with matching agency_id in BOTH tables travel_id | agency_id | customer_id | agency_name 2 | 1002 | 101 | Happy Travel 3 | 1003 | 102 | Global Tours define view ZV_TRAVEL_AGENCY as select from /dmo/travel as t inner join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, agency_id, customer_id, a.agency_name } &lt;-- KEYWORD &#x25B8; Use when you need ONLY records that exist in both sources (e.g., valid bookings with confirmed agencies). &#x25B8; Fastest join type — smallest result set, best index usage. LEFT OUTER JOIN Table A Table B ALL A Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier Agency 1002 | Happy Travel RESULT: ALL rows from A — B columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier Agency ← matched 2 | 1002 | 101 | Happy Travel ← matched 3 | 1003 | 102 | Global Tours ← matched 4 | 9999 | 103 | NULL ← NO match in B! define view ZV_TRAVEL_WITH_AGENCY as select from /dmo/travel as t left outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_name } --> a.agency_name is NULL when no match &#x25B8; Use when you need ALL rows from the left table regardless of whether a match exists on the right. &#x25B8; Right table columns show NULL where there is no matching row — handle with COALESCE in production code. RIGHT OUTER JOIN Table A Table B ALL B Table A (LEFT): /dmo/travel travel_id | agency_id 1 | 1001 2 | 1002 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier 1002 | Happy Travel 1003 | Global Tours RESULT: ALL rows from B — A columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier ← matched 2 | 1002 | 101 | Happy Travel ← matched NULL | 1003 | NULL | Global Tours ← NO match in A! define view ZV_AGENCY_WITH_TRAVEL as select from /dmo/travel as t right outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_id, agency_name } --> travel_id is NULL when no match &#x25B8; Mirror of LEFT JOIN — all rows from the RIGHT table are preserved, left side gets NULLs. &#x25B8; Less common in CDS — typically you swap the tables and use LEFT JOIN for readability. CROSS JOIN (Cartesian Product) Table A: Colors id | color 1 | Red 2 | Blue 3 | Green Table B: Sizes id | size 1 | S 2 | M × Result (3 × 2 = 6 rows) color | size Red | S Red | M Blue | S Blue | M Green | S Green | M define view ZV_COLOR_SIZE as select from colors -- no ON condition! cross join sizes { color, size } &#x25B8; Every row from A paired with every row from B — no ON condition, no filter. &#x25B8; Result size = N(A) × N(B). Use with date dimensions, number ranges, or small reference tables. &#x25B8; ⚠ DANGER: Joining two large tables (10K × 10K = 100M rows) will crash the HANA compiler. Quick Reference INNER Only matching rows from both sides Best performance, smallest result LEFT All rows from LEFT table + matched right columns Good — left table drives cardinality RIGHT All rows from RIGHT table + matched left columns Same as LEFT (swap tables instead) CROSS Every combination — Cartesian product ⚠ Slow — N×M rows | CDS Source Code ","detailsText":"- Combining master data with a date dimension - Generating all possible combinations for matrix reports - Analytical scenarios where every N:M combination is needed - Value help combinations (e.g., all products × all plants) THIS EXAMPLE: Cross-joining Travel with Agency to show how many combinations exist. In practice, you would filter or aggregate the result. Here we show a simple case with small datasets. DIAGRAM: assets/diagrams/join-types.svg"},{"title":"INNER JOIN between Booking, Customer, and Travel views","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_INNER_JOIN","tags":["cds-views"],"description":"INNER JOIN between Booking, Customer, and Travel views. Key topics: INNER JOIN returns only rows where match exists in both tables. Multiple JOIN conditions are","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ INNER JOIN returns only rows where match exists in both tables ◆ Multiple JOIN conditions are supported with AND/OR parentheses ◆ Table aliases (e.g. _Booking, _Customer) are mandatory with JOINs ◆ All key fields from each source should be included ◆ Use fully qualified field names: alias.field_name | Concept Diagram CDS Join Types — Detailed Visual Guide INNER JOIN Table A Table B ON match Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 &lt;-- no match in B Table B (RIGHT): /dmo/agency agency_id | agency_name 1002 | Happy Travel 1003 | Global Tours RESULT: Only rows with matching agency_id in BOTH tables travel_id | agency_id | customer_id | agency_name 2 | 1002 | 101 | Happy Travel 3 | 1003 | 102 | Global Tours define view ZV_TRAVEL_AGENCY as select from /dmo/travel as t inner join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, agency_id, customer_id, a.agency_name } &lt;-- KEYWORD &#x25B8; Use when you need ONLY records that exist in both sources (e.g., valid bookings with confirmed agencies). &#x25B8; Fastest join type — smallest result set, best index usage. LEFT OUTER JOIN Table A Table B ALL A Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier Agency 1002 | Happy Travel RESULT: ALL rows from A — B columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier Agency ← matched 2 | 1002 | 101 | Happy Travel ← matched 3 | 1003 | 102 | Global Tours ← matched 4 | 9999 | 103 | NULL ← NO match in B! define view ZV_TRAVEL_WITH_AGENCY as select from /dmo/travel as t left outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_name } --> a.agency_name is NULL when no match &#x25B8; Use when you need ALL rows from the left table regardless of whether a match exists on the right. &#x25B8; Right table columns show NULL where there is no matching row — handle with COALESCE in production code. RIGHT OUTER JOIN Table A Table B ALL B Table A (LEFT): /dmo/travel travel_id | agency_id 1 | 1001 2 | 1002 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier 1002 | Happy Travel 1003 | Global Tours RESULT: ALL rows from B — A columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier ← matched 2 | 1002 | 101 | Happy Travel ← matched NULL | 1003 | NULL | Global Tours ← NO match in A! define view ZV_AGENCY_WITH_TRAVEL as select from /dmo/travel as t right outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_id, agency_name } --> travel_id is NULL when no match &#x25B8; Mirror of LEFT JOIN — all rows from the RIGHT table are preserved, left side gets NULLs. &#x25B8; Less common in CDS — typically you swap the tables and use LEFT JOIN for readability. CROSS JOIN (Cartesian Product) Table A: Colors id | color 1 | Red 2 | Blue 3 | Green Table B: Sizes id | size 1 | S 2 | M × Result (3 × 2 = 6 rows) color | size Red | S Red | M Blue | S Blue | M Green | S Green | M define view ZV_COLOR_SIZE as select from colors -- no ON condition! cross join sizes { color, size } &#x25B8; Every row from A paired with every row from B — no ON condition, no filter. &#x25B8; Result size = N(A) × N(B). Use with date dimensions, number ranges, or small reference tables. &#x25B8; ⚠ DANGER: Joining two large tables (10K × 10K = 100M rows) will crash the HANA compiler. Quick Reference INNER Only matching rows from both sides Best performance, smallest result LEFT All rows from LEFT table + matched right columns Good — left table drives cardinality RIGHT All rows from RIGHT table + matched left columns Same as LEFT (swap tables instead) CROSS Every combination — Cartesian product ⚠ Slow — N×M rows | CDS Source Code ","detailsText":"JOIN TYPES IN CDS: INNER JOIN → Only matching rows (default) LEFT OUTER JOIN → All rows from left, NULLs from right RIGHT OUTER JOIN → All rows from right, NULLs from left (rarely used) PERFORMANCE NOTE: The HANA compiler optimizes JOIN order. CDS JOINs are NOT necessarily executed in the order they are written. Use compareFilter for optimization. DIAGRAM: assets/diagrams/join-types.svg"},{"title":"LEFT OUTER JOIN between Travel and Booking","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_LEFT_JOIN","tags":["cds-views"],"description":"LEFT OUTER JOIN between Travel and Booking. Key topics: LEFT OUTER JOIN returns ALL rows from the left table, even. RIGHT OUTER JOIN returns ALL rows from the r","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ LEFT OUTER JOIN returns ALL rows from the left table, even ◆ RIGHT OUTER JOIN returns ALL rows from the right table (mirror) ◆ Use LEFT JOIN when: \"Give me all travels AND their bookings if any\" ◆ Use INNER JOIN when: \"Give me only travels that HAVE bookings\" ◆ NULLs from the non-matching side require COALESCE for safe display | Concept Diagram CDS Join Types — Detailed Visual Guide INNER JOIN Table A Table B ON match Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 &lt;-- no match in B Table B (RIGHT): /dmo/agency agency_id | agency_name 1002 | Happy Travel 1003 | Global Tours RESULT: Only rows with matching agency_id in BOTH tables travel_id | agency_id | customer_id | agency_name 2 | 1002 | 101 | Happy Travel 3 | 1003 | 102 | Global Tours define view ZV_TRAVEL_AGENCY as select from /dmo/travel as t inner join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, agency_id, customer_id, a.agency_name } &lt;-- KEYWORD &#x25B8; Use when you need ONLY records that exist in both sources (e.g., valid bookings with confirmed agencies). &#x25B8; Fastest join type — smallest result set, best index usage. LEFT OUTER JOIN Table A Table B ALL A Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier Agency 1002 | Happy Travel RESULT: ALL rows from A — B columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier Agency ← matched 2 | 1002 | 101 | Happy Travel ← matched 3 | 1003 | 102 | Global Tours ← matched 4 | 9999 | 103 | NULL ← NO match in B! define view ZV_TRAVEL_WITH_AGENCY as select from /dmo/travel as t left outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_name } --> a.agency_name is NULL when no match &#x25B8; Use when you need ALL rows from the left table regardless of whether a match exists on the right. &#x25B8; Right table columns show NULL where there is no matching row — handle with COALESCE in production code. RIGHT OUTER JOIN Table A Table B ALL B Table A (LEFT): /dmo/travel travel_id | agency_id 1 | 1001 2 | 1002 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier 1002 | Happy Travel 1003 | Global Tours RESULT: ALL rows from B — A columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier ← matched 2 | 1002 | 101 | Happy Travel ← matched NULL | 1003 | NULL | Global Tours ← NO match in A! define view ZV_AGENCY_WITH_TRAVEL as select from /dmo/travel as t right outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_id, agency_name } --> travel_id is NULL when no match &#x25B8; Mirror of LEFT JOIN — all rows from the RIGHT table are preserved, left side gets NULLs. &#x25B8; Less common in CDS — typically you swap the tables and use LEFT JOIN for readability. CROSS JOIN (Cartesian Product) Table A: Colors id | color 1 | Red 2 | Blue 3 | Green Table B: Sizes id | size 1 | S 2 | M × Result (3 × 2 = 6 rows) color | size Red | S Red | M Blue | S Blue | M Green | S Green | M define view ZV_COLOR_SIZE as select from colors -- no ON condition! cross join sizes { color, size } &#x25B8; Every row from A paired with every row from B — no ON condition, no filter. &#x25B8; Result size = N(A) × N(B). Use with date dimensions, number ranges, or small reference tables. &#x25B8; ⚠ DANGER: Joining two large tables (10K × 10K = 100M rows) will crash the HANA compiler. Quick Reference INNER Only matching rows from both sides Best performance, smallest result LEFT All rows from LEFT table + matched right columns Good — left table drives cardinality RIGHT All rows from RIGHT table + matched left columns Same as LEFT (swap tables instead) CROSS Every combination — Cartesian product ⚠ Slow — N×M rows | CDS Source Code ","detailsText":"when there is no match in the right table (right-side fields = NULL) REAL-WORLD USE CASE: Travels with optional bookings — some travels have no bookings yet. A LEFT JOIN shows all travels; an INNER JOIN would HIDE unbooked travels. DIAGRAM: assets/diagrams/join-types.svg"},{"title":"Consuming association fields via path expressions","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_PATH_EXPR","tags":["associations"],"description":"Consuming association fields via path expressions. Key topics: Path expressions traverse associations using dot notation:. Only works with cardinality [1] or [0","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Path expressions traverse associations using dot notation: ◆ Only works with cardinality [1] or [0..1] — the framework needs ◆ The framework generates the necessary JOIN automatically — ◆ Multiple levels are supported: _Assoc1._Assoc2.Field ◆ Path expressions can also be used in WHERE clause | CDS Source Code ","detailsText":"_AssociationAlias.FieldName → resolves to the associated field to guarantee at most one row to avoid ambiguity no explicit JOIN syntax needed SYNTAX: define view ... as select from SourceView { _AssociationAlias.Field1, _AssociationAlias.Field2 } The association must exist on the source view AND be exposed publicly. Here we consume ZPRAC_CDS_ASSOCIATION which exposes _Customer publicly. COMPARE WITH JOIN: This version is CLEANER than writing a JOIN — the association definition is centralized in one place (ZPRAC_CDS_ASSOCIATION) and reused here."},{"title":"RIGHT OUTER JOIN — all rows from right side preserved","phase":3,"phaseName":"Joins & Associations","category":"Joins & Associations","url":"docs.html#ZPRAC_CDS_RIGHT_JOIN","tags":["cds-views"],"description":"RIGHT OUTER JOIN — all rows from right side preserved. Key topics: RIGHT OUTER JOIN returns ALL rows from the RIGHT table, with. RIGHT JOIN is the mirror of LEF","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ RIGHT OUTER JOIN returns ALL rows from the RIGHT table, with ◆ RIGHT JOIN is the mirror of LEFT JOIN — they produce the same ◆ RIGHT JOIN is RARELY used in practice because LEFT JOIN reads ◆ Use RIGHT JOIN when: \"Give me all bookings AND their travel ◆ SAP CDS supports: LEFT OUTER JOIN, RIGHT OUTER JOIN, INNER JOIN | Concept Diagram CDS Join Types — Detailed Visual Guide INNER JOIN Table A Table B ON match Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 &lt;-- no match in B Table B (RIGHT): /dmo/agency agency_id | agency_name 1002 | Happy Travel 1003 | Global Tours RESULT: Only rows with matching agency_id in BOTH tables travel_id | agency_id | customer_id | agency_name 2 | 1002 | 101 | Happy Travel 3 | 1003 | 102 | Global Tours define view ZV_TRAVEL_AGENCY as select from /dmo/travel as t inner join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, agency_id, customer_id, a.agency_name } &lt;-- KEYWORD &#x25B8; Use when you need ONLY records that exist in both sources (e.g., valid bookings with confirmed agencies). &#x25B8; Fastest join type — smallest result set, best index usage. LEFT OUTER JOIN Table A Table B ALL A Table A (LEFT): /dmo/travel travel_id | agency_id | customer_id 1 | 1001 | 100 2 | 1002 | 101 3 | 1003 | 102 4 | 9999 | 103 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier Agency 1002 | Happy Travel RESULT: ALL rows from A — B columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier Agency ← matched 2 | 1002 | 101 | Happy Travel ← matched 3 | 1003 | 102 | Global Tours ← matched 4 | 9999 | 103 | NULL ← NO match in B! define view ZV_TRAVEL_WITH_AGENCY as select from /dmo/travel as t left outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_name } --> a.agency_name is NULL when no match &#x25B8; Use when you need ALL rows from the left table regardless of whether a match exists on the right. &#x25B8; Right table columns show NULL where there is no matching row — handle with COALESCE in production code. RIGHT OUTER JOIN Table A Table B ALL B Table A (LEFT): /dmo/travel travel_id | agency_id 1 | 1001 2 | 1002 Table B (RIGHT): /dmo/agency agency_id | agency_name 1001 | Premier 1002 | Happy Travel 1003 | Global Tours RESULT: ALL rows from B — A columns are NULL where no match travel_id | agency_id | customer_id | agency_name 1 | 1001 | 100 | Premier ← matched 2 | 1002 | 101 | Happy Travel ← matched NULL | 1003 | NULL | Global Tours ← NO match in A! define view ZV_AGENCY_WITH_TRAVEL as select from /dmo/travel as t right outer join /dmo/agency as a on t.agency_id = a.agency_id { key travel_id, a.agency_id, agency_name } --> travel_id is NULL when no match &#x25B8; Mirror of LEFT JOIN — all rows from the RIGHT table are preserved, left side gets NULLs. &#x25B8; Less common in CDS — typically you swap the tables and use LEFT JOIN for readability. CROSS JOIN (Cartesian Product) Table A: Colors id | color 1 | Red 2 | Blue 3 | Green Table B: Sizes id | size 1 | S 2 | M × Result (3 × 2 = 6 rows) color | size Red | S Red | M Blue | S Blue | M Green | S Green | M define view ZV_COLOR_SIZE as select from colors -- no ON condition! cross join sizes { color, size } &#x25B8; Every row from A paired with every row from B — no ON condition, no filter. &#x25B8; Result size = N(A) × N(B). Use with date dimensions, number ranges, or small reference tables. &#x25B8; ⚠ DANGER: Joining two large tables (10K × 10K = 100M rows) will crash the HANA compiler. Quick Reference INNER Only matching rows from both sides Best performance, smallest result LEFT All rows from LEFT table + matched right columns Good — left table drives cardinality RIGHT All rows from RIGHT table + matched left columns Same as LEFT (swap tables instead) CROSS Every combination — Cartesian product ⚠ Slow — N×M rows | CDS Source Code ","detailsText":"matching data from the LEFT when available (otherwise NULLs) result if you swap the table order more naturally: \"From this main table, join that related table\" info if the travel exists\" (Bookings as the primary entity) LEFT vs RIGHT vs INNER: INNER JOIN → Only matching: Travel A + Booking A LEFT JOIN → ALL Travel: Travel A + Booking A, Travel B + NULL RIGHT JOIN → ALL Booking: Travel A + Booking A, NULL + Booking C DIAGRAM: assets/diagrams/join-types.svg"},{"title":"EXISTS and NOT EXISTS subqueries in WHERE clause","phase":4,"phaseName":"Aggregation & Subqueries","category":"Aggregation & Subqueries","url":"docs.html#ZPRAC_CDS_EXISTS","tags":["subqueries"],"description":"EXISTS and NOT EXISTS subqueries in WHERE clause. Key topics: EXISTS checks if at least one row exists in the subquery. NOT EXISTS ensures NO rows exist in the ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ EXISTS checks if at least one row exists in the subquery ◆ NOT EXISTS ensures NO rows exist in the subquery ◆ The subquery is CORRELATED — it references outer query fields ◆ EXISTS is often more efficient than LEFT JOIN + NULL check ◆ EXISTS stops scanning as soon as one match is found | CDS Source Code ","detailsText":"EXISTS vs JOIN: ┌──────────────┬───────────────────────────┬─────────────────────┐ │ Scenario │ EXISTS │ JOIN │ ├──────────────┼───────────────────────────┼─────────────────────┤ │ \"Has at least│ EXISTS + correlated subq │ JOIN + DISTINCT │ │ one XXX\" │ (stops on first match) │ (processes all rows)│ │ \"Has no XXX\" │ NOT EXISTS (can use index) │ LEFT JOIN + NULL │ └──────────────┴───────────────────────────┴─────────────────────┘ USE CASES: EXISTS: Find travels that have at least one 'New' (N) booking NOT EXISTS: Find travels that have NO 'Accepted' (B) bookings"},{"title":"Aggregation with GROUP BY on Booking data","phase":4,"phaseName":"Aggregation & Subqueries","category":"Aggregation & Subqueries","url":"docs.html#ZPRAC_CDS_GROUP_BY","tags":["cds-views"],"description":"Aggregation with GROUP BY on Booking data. Key topics: All non-aggregated fields in the SELECT list MUST be in GROUP BY. Available aggregate functions:. Aggrega","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ All non-aggregated fields in the SELECT list MUST be in GROUP BY ◆ Available aggregate functions: ◆ Aggregation produces a new semantic layer — @Semantics annotations ◆ GROUP BY fields are implicitly keys of the aggregated result | CDS Source Code ","detailsText":"┌──────────────────┬────────────────────────────────┐ │ Function │ Description │ ├──────────────────┼────────────────────────────────┤ │ COUNT(*) │ Number of rows in group │ │ COUNT( field ) │ Number of non-NULL values │ │ COUNT(DISTINCT x)│ Unique non-NULL values │ │ SUM( field ) │ Total (numeric only) │ │ AVG( field ) │ Average (numeric only) │ │ MIN( field ) │ Minimum value │ │ MAX( field ) │ Maximum value │ │ STRING_AGG(...) │ Concatenate strings (HANA) │ └──────────────────┴────────────────────────────────┘ should be added to aggregated fields for downstream consumption USE CASE: Per-customer booking summary: how many bookings, total spent, average price, cheapest and most expensive flight."},{"title":"Filter aggregated results using HAVING clause","phase":4,"phaseName":"Aggregation & Subqueries","category":"Aggregation & Subqueries","url":"docs.html#ZPRAC_CDS_HAVING","tags":["aggregation"],"description":"Filter aggregated results using HAVING clause. Key topics: HAVING filters after GROUP BY — WHERE filters before GROUP BY. HAVING can reference aggregated fields","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ HAVING filters after GROUP BY — WHERE filters before GROUP BY ◆ HAVING can reference aggregated fields (SUM, COUNT, etc.) ◆ WHERE cannot reference aggregated fields — use HAVING instead ◆ HAVING conditions can include AND/OR just like WHERE | CDS Source Code ","detailsText":"EXECUTION ORDER (conceptual): FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY USE CASE: Find customers who are high-value: total spend > 1000 AND at least 3 bookings. Only interested in customers with more than 1 distinct airline (they fly different carriers)."},{"title":"UNION and UNION ALL — combining two queries vertically","phase":4,"phaseName":"Aggregation & Subqueries","category":"Aggregation & Subqueries","url":"docs.html#ZPRAC_CDS_UNION","tags":["subqueries"],"description":"UNION and UNION ALL — combining two queries vertically. Key topics: UNION ALL: Combines results of two SELECTs (duplicates allowed). UNION:     Same as UNION AL","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ UNION ALL: Combines results of two SELECTs (duplicates allowed) ◆ UNION: Same as UNION ALL but removes duplicates (uses sort) ◆ Both queries must have the SAME NUMBER of columns with ◆ Column names are taken from the FIRST SELECT ◆ UNION ALL is FASTER than UNION because it doesn't sort for dedup ◆ ORDER BY sorts the final combined result (applied at the end) ◆ @Semantics annotations on UNION fields apply to the combined result. | CDS Source Code ","detailsText":"COMPATIBLE data types Each SELECT's column type must match; annotations use the first SELECT's field names. USE CASE: Combine Travel and Booking into a single timeline of events. Travel is the \"header\", Booking is the \"item\". A RecordType discriminator identifies which kind each row is."},{"title":"NULL handling with COALESCE and NULLIF","phase":5,"phaseName":"Built-in Functions","category":"Built-in Functions","url":"docs.html#ZPRAC_CDS_COALESCE","tags":["functions"],"description":"NULL handling with COALESCE and NULLIF. Key topics: COALESCE(val1, val2, ...) returns the first non-NULL value. Use COALESCE to provide defaults when database f","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ COALESCE(val1, val2, ...) returns the first non-NULL value ◆ Use COALESCE to provide defaults when database fields are NULL ◆ NULLIF(a, b) returns NULL if a = b, otherwise returns a ◆ In arithmetic, NULL propagates: total_price + 10 = NULL if total_price is NULL ◆ Always COALESCE nullable fields before using in calculations ◆ @Semantics.amount.currencyCode is essential for monetary fields | CDS Source Code ","detailsText":"to enable proper currency handling in downstream consumers COMMON USE CASES: ┌────────────────────────────────┬──────────────────────────────┐ │ Scenario │ COALESCE Usage │ ├────────────────────────────────┼──────────────────────────────┤ │ Optional amounts (fee, price) │ COALESCE(amount, 0) │ │ Optional text (description) │ COALESCE(text, 'No desc') │ │ NULL-safe arithmetic │ COALESCE(a,0) + COALESCE(b,0)│ │ Suppress equal values │ NULLIF(begin_date, end_date) │ └────────────────────────────────┴──────────────────────────────┘"},{"title":"Currency conversion and decimal shift in CDS","phase":5,"phaseName":"Built-in Functions","category":"Built-in Functions","url":"docs.html#ZPRAC_CDS_CURR_CONV","tags":["cds-views"],"description":"Currency conversion and decimal shift in CDS. Key topics: CURRENCY_CONVERSION converts amounts between currencies using. DECIMAL_SHIFT adjusts decimal places ba","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ CURRENCY_CONVERSION converts amounts between currencies using ◆ DECIMAL_SHIFT adjusts decimal places based on currency (e.g. JPY has 0 decimals) ◆ Both require @Semantics.amount.currencyCode annotation on the result ◆ Key parameters for CURRENCY_CONVERSION: | CDS Source Code ","detailsText":"exchange rate table TCURR (or custom) ┌───────────────────┬──────────────────────────────────────┐ │ Parameter │ Description │ ├───────────────────┼──────────────────────────────────────┤ │ amount │ Source amount to convert │ │ source_currency │ Original currency code │ │ target_currency │ Desired currency code │ │ exchange_rate_date│ Date for rate lookup │ │ round │ 'X' = round, ' ' = truncate │ │ decimal_shift │ 'X' = auto-shift, ' ' = no shift │ │ decimal_shift_round│ Round after shift ('X' / ' ') │ │ error_handling │ 'FAIL' / 'SET_TO_NULL' / 'KEEP' │ └───────────────────┴──────────────────────────────────────┘ REQUIREMENTS: - Exchange rates must exist in TCURR (or custom rate table) - Currency must have configuration in TCUR* tables"},{"title":"Date and time manipulation in CDS","phase":5,"phaseName":"Built-in Functions","category":"Built-in Functions","url":"docs.html#ZPRAC_CDS_DATE_FUNC","tags":["cds-views"],"description":"Date and time manipulation in CDS","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":"Available date/time functions in ABAP CDS: ┌────────────────────────┬────────────────────────────────────────┐ │ Function │ Description │ ├────────────────────────┼────────────────────────────────────────┤ │ DATS_ADD_DAYS(d, n) │ Add days to date │ │ DATS_ADD_MONTHS(d, n) │ Add months to date │ │ DATS_DAYS_BETWEEN(d1,d2)│ Days between two dates │ │ DATS_IS_VALID(d) │ Check if date is valid (1=valid) │ │ TSTMP_TO_DATS(t) │ Timestamp → date │ │ TSTMP_TO_TIMS(t) │ Timestamp → time │ │ ABAP_NOW( ) │ Current timestamp (TSTMP) │ │ ABAP_CURRENT_DATE( ) │ Current date (DATS) │ │ ABAP_CURRENT_TIME( ) │ Current time (TIMS) │ │ TSTMP_SECONDS_BETWEEN │ Seconds between two timestamps │ └────────────────────────┴────────────────────────────────────────┘ DATA TYPE REFERENCE: abap.dats → Date (YYYYMMDD), 8 chars abap.tims → Time (HHMMSS), 6 chars abap.tstmp → Timestamp (YYYYMMDDHHMMSS), 14 chars (without dec.)"},{"title":"Comprehensive string manipulation in CDS","phase":5,"phaseName":"Built-in Functions","category":"Built-in Functions","url":"docs.html#ZPRAC_CDS_STRING_FUNC","tags":["cds-views"],"description":"Comprehensive string manipulation in CDS","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":"Available string functions in ABAP CDS: ┌─────────────────────┬──────────────────────────────────────────┐ │ Function │ Description │ ├─────────────────────┼──────────────────────────────────────────┤ │ CONCAT(a, b) │ Concatenate two strings │ │ CONCAT(a, sep, b) │ Concatenate with separator (3 args) │ │ CONCAT_WITH_SPACE │ Concatenate with N spaces between │ │ SUBSTRING(s, p, l) │ Extract substring from position, length │ │ LEFT(s, l) │ First l characters │ │ RIGHT(s, l) │ Last l characters │ │ LENGTH(s) │ Character count │ │ REPLACE(s, old, new)│ Replace all occurrences │ │ ABAP_UPPER(s) │ Uppercase (locale-aware) │ │ ABAP_LOWER(s) │ Lowercase (locale-aware) │ │ LTRIM(s, c) │ Remove leading characters │ │ RTRIM(s, c) │ Remove trailing characters │ │ INSTR(s, substr) │ Position of substring (1-based) │ │ STRPOS(s, substr) │ Position of substring (0 if not found) │ └─────────────────────┴──────────────────────────────────────────┘"},{"title":"VDM Basic (Interface) View — the foundation layer","phase":6,"phaseName":"Virtual Data Model (VDM)","category":"Virtual Data Model (VDM)","url":"docs.html#ZPRAC_CDS_VDM_BASIC","tags":["cds-view","vdm"],"description":"VDM Basic (Interface) View — the foundation layer","sections":["Concept Diagram","CDS Source Code"],"sectionsText":"Concept Diagram VDM (Virtual Data Model) Layer Architecture Consumption View (Layer 4) C_* or R_* prefix · Fiori UI / OData · @UI.* / @Search / @Consumption.* annotations consumes Composite View (Layer 3) C_* prefix · Joins multiple Basic views · Business logic, aggregations, currency conversion Example: C_Travel_Agency — joins Travel + Agency + Booking Basic / Interface View (Layer 2) I_* prefix · Reusable data foundation · Field selection, aliases, simple filters Example: I_Travel / I_Booking — clean projection of DDIC tables Private View (Layer 1) P_* prefix or no prefix · Internal abstraction · Complex joins, data enrichment, no UI annotations Example: P_Travel_Aggregate — aggregation logic hidden from consumers HANA DB / DDIC Tables /DMO/I_Travel_D / /DMO/I_Booking_D / /DMO/I_Agency / ... VDM Naming Convention & Layer Purpose Prefix Layer Purpose Annotations Consumed By C_* / R_* Consumption Fiori UI, OData exposure @UI.*, @Search, @Consumption.* Fiori App / External API C_* Composite Business logic, joins, aggregations @ObjectModel.*, @Analytics.* Consumption views I_* Basic / Interface Reusable data foundation @AccessControl.*, @EndUserText.* Composite views P_* / none Private Internal logic, hidden from consumers No UI annotations Basic / Composite views | CDS Source Code ","detailsText":"WHAT IS VDM? SAP's Virtual Data Model standardizes CDS view development into layered view types. Following VDM ensures: ✓ Consistent naming and structure across the organization ✓ Clear separation of concerns between layers ✓ Easier maintenance and onboarding of new developers ✓ Reusable building blocks for Fiori, Analytics, and OData VDM VIEW TYPES: ┌──────────────┬──────────┬────────────────────────────────┐ │ Type │ Notation │ Purpose │ ├──────────────┼──────────┼────────────────────────────────┤ │ #BASIC │ I_* │ Interface - direct table access│ │ #COMPOSITE │ C_* │ Business logic / calculations │ │ #CONSUMPTION │ C_* │ Final layer for consumers │ │ #PRIVATE │ P_* │ Internal helpers (not consumed)│ └──────────────┴──────────┴────────────────────────────────┘ BASIC VIEW CHARACTERISTICS: - Directly built on database tables or other #BASIC views - No/minimal business logic — pure data projection - Full field semantics (@Semantics.amount, @Semantics.date, etc.) - Named with I_ prefix in SAP standard: e.g. I_Travel_D - Foundation for all downstream composite/consumption views THIS EXAMPLE: @VDM.viewType: #BASIC → Marks this as an Interface/Basic view @Analytics.dataCategory: #DIMENSION → Used as a dimension in analytics @ObjectModel.dataType: #BASIC → Core data type All fields have full @Semantics annotations (VDM requirement) DIAGRAM: assets/diagrams/vdm-layers.svg"},{"title":"VDM Composite View — business logic layer","phase":6,"phaseName":"Virtual Data Model (VDM)","category":"Virtual Data Model (VDM)","url":"docs.html#ZPRAC_CDS_VDM_COMPOSITE","tags":["vdm"],"description":"VDM Composite View — business logic layer","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":""},{"title":"VDM Consumption View — final layer for Fiori / Analytics","phase":6,"phaseName":"Virtual Data Model (VDM)","category":"Virtual Data Model (VDM)","url":"docs.html#ZPRAC_CDS_VDM_CONSUME","tags":["vdm"],"description":"VDM Consumption View — final layer for Fiori / Analytics","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":""},{"title":"consumable","phase":6,"phaseName":"Virtual Data Model (VDM)","category":"Virtual Data Model (VDM)","url":"docs.html#ZPRAC_CDS_VDM_PRIVATE","tags":["vdm"],"description":"VDM Private View — internal helper / non-consumable. Key topics: #PRIVATE views are INTERNAL helper views — not consumed by. They are consumed by other CDS view","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ #PRIVATE views are INTERNAL helper views — not consumed by ◆ They are consumed by other CDS views (#BASIC, #COMPOSITE, etc.) ◆ Characteristics: ◆ Use #PRIVATE views for: ◆ #PRIVATE is the default viewType if no @VDM.viewType is specified | CDS Source Code ","detailsText":"end-user applications (Fiori, OData, Analytics) ✓ Contains shared logic used by multiple public views ✓ Avoids code duplication across the CDS layer ✓ Is not exposed via OData (no @OData.publish) ✓ Named with P_ prefix in SAP standard ✓ Called \"Private\" because they are invisible to consumers - Common calculation patterns reused across views - Data transformation/complex joins used internally - SQLScript-based logic wrapped for reuse - Text retrieval logic for language-dependent fields VDM VIEW TYPE HIERARCHY: PRIVATE → BASIC → COMPOSITE → CONSUMPTION (Lowest) (Highest)"},{"title":"Metadata Extension pattern (separating UI annotations)","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_MDX_EXT","tags":["cds-views"],"description":"Metadata Extension pattern (separating UI annotations)","sections":["CDS Source Code"],"sectionsText":"CDS Source Code ","detailsText":"WHAT IS A METADATA EXTENSION? A separate CDS artifact that adds UI/analytics annotations on top of an existing CDS view WITHOUT modifying the view itself. BENEFITS: ✓ The core data model stays clean (no UI annotations mixed in) ✓ Different consumers can have different metadata extensions ✓ Upgrade-safe — core view doesn't change when UI requirements change ✓ Multiple extensions can be stacked HOW IT WORKS: 1. The base view has @Metadata.allowExtensions: true 2. A separate .asr file (Metadata Extension) uses ANNOTATE VIEW 3. The extension is activated independently 4. SAP S/4HANA uses this extensively for Fiori apps SYNTAX OF METADATA EXTENSION: @Metadata.layer: #CORE // Who owns this: #CORE / #CUSTOMER / #PARTNER annotate view ZPRAC_CDS_MDX_EXT with { @UI.facet : [ { ... } ] @UI.lineItem : [ { position: 10 } ] FieldName; } IMPORTANT: Base views with @Metadata.allowExtensions: true should still include all @Semantics annotations on fields — the metadata extension only adds UI-specific annotations, not semantic/analytic annotations."},{"title":"CDS View with OData draft enablement for transactional UIs","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_ODATA_DRAFT","tags":["odata"],"description":"CDS View with OData draft enablement for transactional UIs. Key topics: @OData.draft.enabled: true enables draft handling for the entity. Draft allows users to ","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @OData.draft.enabled: true enables draft handling for the entity ◆ Draft allows users to save incomplete changes before publishing ◆ Requirements for draft-enabled CDS views: ◆ Draft views work with RAP (ABAP RESTful Application Programming Model) ◆ The draft key fields (DraftUUID, DraftAdministrativeData) are ◆ Draft views CANNOT be consumed without RAP BO behavior definition | CDS Source Code ","detailsText":"✓ @ObjectModel.writeDraft: true (or @ObjectModel.writeDraft pointing to a separate draft-enabled view) ✓ @OData.draft.enabled: true ✓ @ObjectModel.compositionRoot: true ✓ @ObjectModel.createEnabled, .updateEnabled, .deleteEnabled: true automatically added by the framework — this annotation is the STARTING point DRAFT LIFECYCLE: Create Draft → Save Draft → Activate → Delete Draft The framework manages IsActiveEntity, DraftUUID, etc. automatically. NOTE: This view demonstrates the annotations only. A full draft scenario also requires RAP behavior definition (BDEF), service definition, and service binding — beyond the scope of this CDS reference."},{"title":"text search with @Search annotations","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_SEARCH","tags":["fiori"],"description":"Full-text search with @Search annotations. Key topics: @Search.searchable enables full-text search on a CDS view. Fields annotated with @Search.defaultSearchEle","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @Search.searchable enables full-text search on a CDS view ◆ Fields annotated with @Search.defaultSearchElement are included ◆ @Search.fuzzinessThreshold controls fuzzy matching (0.0 - 1.0) ◆ @Search.ranking defines search result ranking (TITLE / SUMMARY / LOW) ◆ Search is case-insensitive by default ◆ The Fiori search bar uses these annotations automatically | CDS Source Code ","detailsText":"in the global search SEARCH ANNOTATION REFERENCE: ┌──────────────────────────────┬────────────────────────────────┐ │ Annotation │ Description │ ├──────────────────────────────┼────────────────────────────────┤ │ @Search.searchable │ Enable search for the view │ │ @Search.defaultSearchElement │ Include in global search │ │ @Search.fuzzinessThreshold │ 0.0 (exact) to 1.0 (very fuzzy)│ │ @Search.ranking: #TITLE │ Highest relevance │ │ @Search.ranking: #SUMMARY │ Medium relevance │ │ @Search.ranking: #LOW │ Low relevance │ └──────────────────────────────┴────────────────────────────────┘ ENTERPRISE SEARCH MODELS (ESH): A separate CDS artifact (`define search model`) that connects CDS views to SAP Enterprise Search (ESH) for federated full-text search across multiple business objects. Unlike @Search.searchable (Fiori search bar), Enterprise Search: - Uses a dedicated `define search model` artifact - Can search across multiple CDS views simultaneously - Requires ESH infrastructure and indexing - Supports federated search (BW, ERP, CRM data together) Example (conceptual — requires ESH setup): @Search.searchable: true define search model ZPRAC_ESH_TRAVEL on ZPRAC_CDS_SEARCH { key TravelId; field Description with relevance: #HIGH; field AgencyId with relevance: #MEDIUM; } NOTE: Enterprise Search is being modernized by SAP's Federated Search strategy. Prefer @Search.searchable for Fiori apps and @Analytics.query for analytical search."},{"title":"Service Definition & Binding — Exposing CDS views as OData services for Fiori Elements","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_SERVICE_EXPOSE","tags":["cds-views"],"description":"Service Definition & Binding — Exposing CDS views as OData services for Fiori Elements. Key topics: Service Definition is the contract — it selects which CDS vi","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Service Definition is the contract — it selects which CDS views ◆ Service Binding binds the definition to a protocol (OData v2 / ◆ UI5 / Fiori Elements preview is launched directly from the ◆ Draft-enabled views (@OData.draft.enabled) require explicit ◆ $select (projection) and $expand (navigation) behavior depends ◆ SAP Gateway (SEGW) vs RAP-based exposure: ◆ Clean-core best practices: use RAP-based exposure, keep | CDS Source Code ","detailsText":"are exposed and under which alias names for the OData service OData v4 / InA) and a transport request, enabling Fiori preview Service Binding in ADT (right-click → Open Fiori Elements App) draft handling via RAP behavior — read-only views do not on the exposed associations in the Service Definition ┌────────────┬──────────────────────┬──────────────────────┐ │ Aspect │ Gateway (SEGW) │ RAP-based │ ├────────────┼──────────────────────┼──────────────────────┤ │ Approach │ Classic, model-based │ Code-pushdown, CDS │ │ Perform. │ Server-side │ Database-pushdown │ │ Draft │ Manual handling │ Automatic via BDEF │ │ Cloud-ready│ No │ Yes │ └────────────┴──────────────────────┴──────────────────────┘ Service Definitions focused on one business object, avoid exposing tables directly, and use view entities (CDS VE) instead of classic views SERVICE BINDING REFERENCE (in ADT): ┌──────────────────────────────────────────────────────────────┐ │ Service Definition: ZPRAC_SERVICE_TRAVEL │ │ Service Binding: ZPRAC_BINDING_TRAVEL │ │ Binding Type: OData v4 - UI5 Service │ │ Transport: 123456 │ │ Fiori Preview URL: /sap/opu/odata4/sap/ZPRAC_TRAVEL/… │ │ │ │ Steps in ADT: │ │ 1. New → Service Definition → select CDS root VE │ │ 2. Add EXPOSE statements for child entities │ │ 3. New → Service Binding → choose Service Definition │ │ 4. Set binding type = OData v4 - UI5 Service │ │ 5. Activate → right-click → Open Fiori Elements App │ └──────────────────────────────────────────────────────────────┘ USAGE IN ABAP (Fiori app consumption via /UI5/ABAP): The OData service is consumed by a Fiori Elements app using the SAPUI5 manifest.json: \"dataSources\": { \"travelService\": { \"uri\": \"/sap/opu/odata4/sap/ZPRAC_TRAVEL/\", \"type\": \"OData\", \"settings\": { \"odataVersion\": \"4.0\" } } }, \"models\": { \"\": { \"dataSource\": \"travelService\" } } The Fiori app uses smart controls (SmartTable, SmartForm, etc.) which read @UI annotations from the CDS metadata to auto-generate columns, filters, and object pages — no manual OData calls needed."},{"title":"UI annotations for Fiori — @UI.lineItem, @UI.identification, etc.","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_UI_ANNOT","tags":["rap"],"description":"UI annotations for Fiori — @UI.lineItem, @UI.identification, etc.. Key topics: @UI annotations are consumed by Fiori Elements to generate the UI. Common @UI ann","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @UI annotations are consumed by Fiori Elements to generate the UI ◆ Common @UI annotation categories: ◆ @UI annotations are declared in METADATA EXTENSIONS (.asr) ◆ @UI annotations do NOT affect the data result — only the UI ◆ Position numbers determine field order in the UI | CDS Source Code ","detailsText":"┌──────────────────────┬─────────────────────────────────────┐ │ Annotation │ Purpose │ ├──────────────────────┼─────────────────────────────────────┤ │ @UI.lineItem │ Column in list/table view │ │ @UI.identification │ Field in object page header │ │ @UI.selectionField │ Filter in selection screen │ │ @UI.hidden │ Hide field from UI │ │ @UI.headerInfo │ Title/description for object page │ │ @UI.facet │ Sections/tabs on object page │ │ @UI.badge │ Show as badge/indicator │ │ @UI.consolidation │ Consolidation behavior │ │ @UI.creationRow │ Create mode visibility │ └──────────────────────┴─────────────────────────────────────┘ in production, but shown here inline for learning purposes"},{"title":"Value help definition for Fiori fields","phase":7,"phaseName":"Fiori & OData","category":"Fiori & OData","url":"docs.html#ZPRAC_CDS_VALUE_HELP","tags":["vdm","fiori"],"description":"Value help definition for Fiori fields. Key topics: Value help provides F4 / dropdown suggestions for fields. Defined using @Consumption.valueHelpDefinition ann","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Value help provides F4 / dropdown suggestions for fields ◆ Defined using @Consumption.valueHelpDefinition annotation ◆ Can point to another CDS view, table, or element list ◆ Key parameters: ◆ Additional annotations: ◆ The VALUE HELP VIEW (ZPRAC_CDS_AGENCY_VH below) is a lightweight | CDS Source Code ","detailsText":"┌────────────────────┬──────────────────────────────────────┐ │ Parameter │ Description │ ├────────────────────┼──────────────────────────────────────┤ │ entity │ CDS view providing the value list │ │ element │ Field in the value help view │ │ label │ Display text for the help │ │ additionalBinding │ Additional return parameters │ │ useForValidation │ Validate input against values │ └────────────────────┴──────────────────────────────────────┘ @Consumption.filter → Defines filter fields for the value help @Consumption.valueHelp → Reference to a specific VH definition view returning only the key + description for the dropdown. It is NOT a separate file — included here for context. VALUE HELP VIEW (for AgencyID): define view ZPRAC_CDS_AGENCY_VH as select from /dmo/agency { key agency_id as AgencyID, name as AgencyName, street as Street, city as City } In production, value help views are often created as separate CDS artifacts following the _VH naming convention."},{"title":"child with dependent lifecycle","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_CDS_COMPOSITION","tags":["associations","rap"],"description":"CDS Composition — parent-child with dependent lifecycle. Key topics: Composition defines a WHOLE-PART relationship where the child. If the parent is deleted, AL","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Composition defines a WHOLE-PART relationship where the child ◆ If the parent is deleted, ALL children are deleted (cascade) ◆ Composition is the foundation of RAP BO (Business Object) modeling ◆ Syntax: composition [0..n] of TargetView as _alias on condition ◆ @ObjectModel.association.type: #TO_COMPOSITION defines in RAP ◆ Cardinality: [0..1] = optional single, [1] = required single, | CDS Source Code ","detailsText":"cannot exist independently from the parent (e.g., Order → Item) [0..n] = optional multi, [1..n] = required multi COMPOSITION vs ASSOCIATION: ┌─────────────┬──────────────────────┬────────────────────┐ │ Aspect │ Composition │ Association │ ├─────────────┼──────────────────────┼────────────────────┤ │ Lifecycle │ Dependent (cascade) │ Independent │ │ Ownership │ Parent owns child │ No ownership │ │ Delete │ Deletes children │ Does not affect │ │ RAP Role │ BO node relationship │ Query relationship │ │ Example │ Travel → Booking │ Booking → Customer │ └─────────────┴──────────────────────┴────────────────────┘ THIS EXAMPLE: Travel is the root entity with Composition to Booking as child. A Booking cannot exist without a Travel."},{"title":"Extensible CDS view — key user field extensibility","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_CDS_EXTENSIBILITY","tags":["rap"],"description":"Extensible CDS view — key user field extensibility. Key topics: @Extensible: true allows customers to add custom fields to. @Extensible: true is set on the BASE","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @Extensible: true allows customers to add custom fields to ◆ @Extensible: true is set on the BASE CDS view (interface view) ◆ Customer fields are added via APPEND structures on the DDIC ◆ The CDS view automatically picks up appended fields at runtime ◆ Prerequisites for extensibility: ◆ Key user extensibility is ONLY available for #BASIC view types ◆ NOT for #COMPOSITE, #CONSUMPTION, or #PRIVATE views | CDS Source Code ","detailsText":"an existing CDS view via the Key User Extensibility framework structure (the SQL view name), NOT directly on the CDS view ✓ @AbapCatalog.sqlViewName must exist as a SE11 structure ✓ The structure must be extensible (delivery class E) ✓ @Extensible: true on the CDS view EXTENSIBILITY FLOW: Customer defines APPEND on ZPRAC_SQL_EXT (SE11) → The append fields are automatically available in the CDS view → Fiori / OData automatically exposes them CUSTOMER APPEND EXAMPLE: TYPES: BEGIN OF ZPRAC_SQL_EXT. INCLUDE TYPE: ZAPPEND_TRAVEL_EXT. \" Customer fields TYPES: END OF ZPRAC_SQL_EXT."},{"title":"CDS Early vs Late Numbering — Key assignment strategies in RAP","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_CDS_NUMBERING","tags":["cds-views"],"description":"CDS Early vs Late Numbering — Key assignment strategies in RAP. Key topics: Early numbering assigns keys BEFORE the creation request reaches. Late numbering ass","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Early numbering assigns keys BEFORE the creation request reaches ◆ Late numbering assigns keys AFTER the database insert — the system ◆ Managed RAP with early numbering: use `with early numbering` in ◆ Managed RAP with late numbering: the database (or CDS view) provides ◆ `@ObjectModel.usageType.serviceQuality: #EARLY_NUMBERING` on the CDS ◆ In unmanaged RAP, numbering is fully manual — the implementation ◆ Draft-enabled BOs typically use early numbering so the draft key | CDS Source Code ","detailsText":"the database — the key is known immediately in the ABAP layer. uses a number range or database sequence to generate the key. the behavior definition; keys are assigned in the `early_numbering` method or via `ETAG` / `NUMBER` mapping. the key; the RAP framework reads it back after the `save` sequence. element hints at the intended strategy for service contracts. class handles key assignment with `number object` or `UUID` creation. is known before the first save to the draft table. COMPARISON: Early vs Late vs Unmanaged Numbering Aspect | Early | Late | Unmanaged --------------------------------------------------------------------------------------------------------- Key source | ABAP (number range / UUID)| DB sequence / identity | Fully manual (class) Key known | Before `save` | After `save` | In implementation method Draft support | Yes (preferred) | Limited | Manual Behavior def syntax | `with early numbering` | `with late numbering` | None (implementation driven) Use case | Fiori transactional | Non-draft / migration | Legacy / custom Etag handling | Before modification | After modification | Implementation decides"},{"title":"@ObjectModel annotations for RAP / OData / Analytics","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_CDS_OBJECT_MODEL","tags":["cds-views"],"description":"@ObjectModel annotations for RAP / OData / Analytics. Key topics: @ObjectModel annotations define the business object structure. They are used by RAP (ABAP REST","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @ObjectModel annotations define the business object structure ◆ They are used by RAP (ABAP RESTful Application Programming Model) ◆ Common @ObjectModel annotations: ◆ These annotations are critical for RAP BO definitions ◆ @ObjectModel.foreignKey.association references the association | CDS Source Code ","detailsText":"for service definition, draft handling, and OData generation ┌────────────────────────────┬────────────────────────────────┐ │ Annotation │ Purpose │ ├────────────────────────────┼────────────────────────────────┤ │ @ObjectModel.foreignKey │ Marks a field as foreign key │ │ @ObjectModel.semanticKey │ Defines the business key │ │ @ObjectModel.representative│ Key that uniquely identifies │ │ @ObjectModel.text │ Language-dependent text │ │ @ObjectModel.association │ Association metadata │ │ @ObjectModel.writeDraft │ Draft-enabled for transaction │ │ @ObjectModel.dataType │ #BASIC / #COMPOSITE / #CUBE │ │ @ObjectModel.compositionRoot│ Root entity of composition │ │ @ObjectModel.template │ Template category │ └────────────────────────────┴────────────────────────────────┘ (not shown here but used in RAP context)"},{"title":"View Extension — extending fields of an existing CDS view","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_CDS_VIEW_EXT","tags":["cds-views"],"description":"View Extension — extending fields of an existing CDS view. Key topics: The extension view must be activated after the base view. Extensions can add new fields o","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ The extension view must be activated after the base view ◆ Extensions can add new fields or provide default values ◆ The base view does not need to know about the extension ◆ Only one level of extension is allowed (no chain extensions) ◆ Extensions are additive — cannot modify/remove existing fields | CDS Source Code ","detailsText":"WHAT IS A VIEW EXTENSION? Different from Metadata Extension (@Metadata.allowExtensions): A View Extension adds NEW FIELDS to an existing CDS view entity. COMPARISON: ┌──────────────────────┬──────────────────────┬────────────────────────┐ │ Feature │ Metadata Extension │ View Extension │ ├──────────────────────┼──────────────────────┼────────────────────────┤ │ File type │ .asr │ .asr │ │ Annotation │ @Metadata.allowExt │ @AbapCatalog.viewExt │ │ Adds UI annotations │ Yes │ No │ │ Adds new fields │ No │ Yes │ │ Used by │ CUSTOMER/PARTNER │ CUSTOMER/PARTNER │ │ Multiple extensions │ Yes (stacked) │ Yes (stacked) │ └──────────────────────┴──────────────────────┴────────────────────────┘ SYNTAX: @AbapCatalog.viewExtension: true define view ZPRAC_CDS_VIEW_EXT as extend view ZPRAC_CDS_SIMPLE with { ... };"},{"title":"based business objects","phase":8,"phaseName":"RAP & Extensibility","category":"RAP & Extensibility","url":"docs.html#ZPRAC_RAP_BEHAVIOR","tags":["rap"],"description":"RAP Behavior Definition — Defining transactional behavior for CDS-based business objects. Key topics: Behavior definition (BDEF) is the RAP contract — it define","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Behavior definition (BDEF) is the RAP contract — it defines ◆ Managed implementation: the RAP framework generates all ◆ `with draft` enables draft-capable transactional UIs — ◆ CRUD operations (create / update / delete) are declared per ◆ `implementation in class ZCL_... unique` binds the behavior ◆ Validations check data consistency before save (e.g., dates, ◆ Actions are custom operations: instance actions operate on ◆ `strict ( 2 )` enforces modern RAP rules (cloud-readiness, | Concept Diagram RAP Architecture — Full Stack Breakdown 1. UI / Presentation Layer SAP Fiori Elements · Freestyle UI5 · OData V4 Client · Web APIs OData V4 Request 2. Service Layer Service Definition → defines what entities are exposed Service Binding → binds to OData V4 UI or Web API protocol EML (Entity Manipulation Language) 3. Behavior Layer Behavior Definition (BDEF) create / update / delete Behavior Implementation ABAP class (local) Draft Handling Draft tables (if active) Authorization Control %control / instance auth reads from 4. Data Model Layer CDS View Entity (Root) define root view entity CDS Projection View define root view entity (projection) Metadata Extension @MetadataExtension: true RAP BO Business Object 5. Database Layer SAP HANA · DDIC Tables · Table Functions · AMDP · ABAP SQL via Open SQL RAP Request Flow — End to End Step Component What Happens 1 Fiori / UI5 User triggers a request (list report, object page, action) 2 Service Binding OData V4 URL → maps to Service Definition entities 3 Behavior Definition EML → routes to create/update/delete or query implementation 4 Behavior Implementation ABAP class: FOR MODIFY / FOR READ methods execute logic 5 CDS View Entity SQL statement generated from CDS → Open SQL → HANA 6 SAP HANA Data returned to EML → serialized to OData V4 JSON → Fiori | CDS Source Code ","detailsText":"what operations (CRUD, actions, validations) are allowed on a CDS view entity and how they behave save/update/delete logic automatically; unmanaged requires manual implementation in a handler class for full control users can save incomplete changes before publishing (activate) node; if omitted, the operation is not allowed to a pool class with handler methods for custom logic mandatory fields); determinations auto-execute on triggers (e.g., set status on create) a single entity (e.g., acceptBooking), static actions on the whole set (e.g., bulkArchive) no obsolete statements, mandatory field controls) KEY RULES — RAP BDEF Requirements: ┌───────────────────────────────────┬─────────────────────────────────┐ │ Rule │ Description │ ├───────────────────────────────────┼─────────────────────────────────┤ │ Root entity must have a │ persistent table /dmo/... │ │ persistent table assigned │ │ │ Child entities must use │ lock dependent by _Parent │ │ lock dependent │ │ │ authorization master (instance) │ Enables instance-based auth │ │ on root node │ │ │ field ( readonly : update ) │ Protect fields from change │ │ for admin fields (CreatedBy, …) │ after creation │ │ field ( mandatory ) for required │ Enforces not-null on create │ │ business fields │ │ │ mapping for ... { ... } │ Maps CDS field names to DB cols │ │ │ │ │ Strict(2) is MANDATORY for │ Required for cloud / SAP BTP │ │ cloud-ready RAP BOs │ │ └───────────────────────────────────┴─────────────────────────────────┘ DIAGRAM: assets/diagrams/rap-arch.svg"},{"title":"CDS Abstract Entities — Structure types for RAP action signatures and API contracts","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_ABSTRACT_ENTITY","tags":["cds-views"],"description":"CDS Abstract Entities — Structure types for RAP action signatures and API contracts. Key topics: `define abstract entity` creates a CDS data type without genera","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ `define abstract entity` creates a CDS data type without generating any ◆ No DDIC or database object is created when activated; abstract entities ◆ They are the primary way to type RAP action parameters, return structures, ◆ Abstract entities can be used as association targets when the association ◆ `ANNOTATE ENTITY ZPRAC_ABST_AIRPORT_DIST` enables metadata extensions | CDS Source Code ","detailsText":"database object — it exists purely as a design-time type contract. are zero-footprint types used only in the CDS / RAP type system. and OData function import signatures without needing a DDIC structure. is never materialised (e.g., a navigation that never needs a join). without changing the source definition — useful for UI annotations. USE CASES FOR ABSTRACT ENTITIES Use Case | Example ------------------------------------------------------------------------- RAP action input parameters | Action Input: ZPRAC_ABST_AIRPORT_DIST RAP action result type | Action Result: ZPRAC_ABST_AIRPORT_DIST OData function import parameters | Function Import: CalculateDistance Association target (no instance) | _Airport as ZPRAC_ABST_Airport Metadata extension target | ANNOTATE ENTITY ZPRAC_ABST_AIRPORT_DIST Remote API communication | Input/output contract for outbound services"},{"title":"client data access","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_CLIENT_HANDLING","tags":["rap"],"description":"Client handling algorithms — multi-client data access. Key topics: @ClientHandling.algorithm controls how the ABAP framework. Available algorithms:. #AUTOMATIC_","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ @ClientHandling.algorithm controls how the ABAP framework ◆ Available algorithms: ◆ #AUTOMATIC_RHS is the DEFAULT — adds AND client = $session.client ◆ #INHERITED: the view does NOT add its own client filter but ◆ Use #PROTECTED for views that should not add client filters ◆ The client field must be present in the view or an error occurs ◆ @Environment.systemField: #CLIENT on the field is good practice | CDS Source Code ","detailsText":"handles the MANDT (client) field ┌────────────────────────┬─────────────────────────────────────┐ │ Algorithm │ Behavior │ ├────────────────────────┼─────────────────────────────────────┤ │ #AUTOMATIC_RHS │ Default — add implicit CLIENT = sy-mandt │ │ #PROTECTED │ Inherit client from source (read-only) │ │ #AUTOMATIC │ Add implicit client (like RHS) │ │ #INHERITED │ Client field inherited from source │ │ #RHS_ONLY │ Only Right-Hand Side implicit filter │ │ #DONT_SHARE │ No client sharing across sources │ │ #NO_CLIENT │ No client handling at all │ └────────────────────────┴─────────────────────────────────────┘ relies on the base view/view's client handling (e.g., cross-client views or local temporary data) USE CASE: Standard views need #AUTOMATIC_RHS (default) to ensure client separation. Cross-client reference data (like currencies, units) may use #INHERITED or #NO_CLIENT."},{"title":"DDIC data sources with ABAP-based data retrieval","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_CUSTOM_ENTITY","tags":["cds-views"],"description":"CDS Custom Entities — Non-DDIC data sources with ABAP-based data retrieval. Key topics: `define custom entity` creates a typed CDS data source without a. `@Obje","sections":["Key Learning Points","Concept Diagram","CDS Source Code"],"sectionsText":"Key Learning Points ◆ `define custom entity` creates a typed CDS data source without a ◆ `@ObjectModel.query.implementedBy: 'ABAP:ZCL_...'` binds the entity to ◆ `define root custom entity` enables full RAP support (transactional ◆ The ABAP class must implement `IF_RAP_QUERY_PROVIDER` for RAP integration ◆ Method IF_RAP_QUERY_PROVIDER~SELECT( ) receives the request filter, ◆ Custom entities are ideal for wrapping external APIs (RFC, SOAP, OData), | Concept Diagram Custom Entity — Data Flow & Implementation End-to-End Data Flow 1. External Request External Source BAPI / RFC / Web API CALL 2. Provider Class ABAP Query Provider IF_RAP_QUERY_PROVIDER~select MAP 3. Custom Entity Custom Entity (CDS) @ObjectModel.query.implementedBy 4. Consumer Consumer OData / Fiori / ABAP Custom Entity — CDS Definition @ObjectModel.query.implementedBy: 'ABAP:ZCL_PRAC_PURCHASE_QUERY' define root view entity ZPRAC_CDS_C_PurchaseOrder as select from ??? -- No FROM clause — data comes from ABAP provider { key PurchaseOrder: abap.char(10); CompanyCode: abap.char(4); ... } ABAP Provider Class Implementation CLASS ZCL_PRAC_PURCHASE_QUERY IMPLEMENTATION. METHOD if_rap_query_provider~select. \" 1. Read parameters DATA(lt_filter) = io_request-&gt;get_filter( ). \" 2. Call external source DATA(lt_data) = call_bapi( lt_filter ). \" 3. Return data io_response-&gt;set_total_number_of_records( lines( lt_data ) ). io_response-&gt;set_data( lt_data ). IF_RAP_QUERY_PROVIDER Interface Methods io_request methods: get_filter( ) → Return filter conditions get_paging( ) → Offset + page size get_sort( ) → Sort order elements get_requested_elements( ) → Selected fields io_response methods: set_data( it_data ) → Return result table set_total_number_of_records( iv_count ) → Total rows When to Use Custom Entities External Data Integration BAPI calls, Web services, RFC-enabled function modules Complex Business Logic Multi-step calculations, conditional aggregations Legacy System Access Read from non-HANA sources, CDS views not possible ⚠ Custom entities have no SELECT from a database table — the FROM clause is absent. ⚠ All data is provided by the ABAP query provider class — you must implement filter/sort/paging yourself. ⚠ Association to custom entities is possible but the target cannot use path expressions (no automatic JOIN). | CDS Source Code ","detailsText":"corresponding database table or DDIC structure — purely definitional. an ABAP class that provides the data at runtime. behaviour, draft, etc.) — without `root` only read access is possible. or `IF_SADL_QUERY_PROVIDER` for plain CDS consumption. sorting, and paging and must return data as an internal table. calling BAPIs, aggregating disparate data sources, or any logic that cannot be expressed in standard SQL. COMPARISON: Custom Entity vs Table Function vs Virtual Element Feature | Custom Entity | Table Function | Virtual Element --------------------------------------------------------------------------------------------------------- Base object | CDS definition only | AMDP / HANA function | CDS projection view Data source | Any ABAP logic / API | HANA SQLScript / SQL | Same DB table as parent Code pushdown | No (ABAP layer) | Yes (HANA layer) | No (ABAP layer) RAP transactional | Yes (define root) | No (read-only) | Yes (in RAP projection) DDL / DML support | No (cannot INSERT/SELECT) | SELECT only | No (computed only) Parameter support | Yes (CDS parameters) | No | No Association target | Yes | Yes | Yes Use case | External API, BAPI, RFC | High-performance SQL algo | Simple ABAP enrichment DIAGRAM: assets/diagrams/custom-entity-flow.svg"},{"title":"child tree structure","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_HIERARCHY","tags":["cds-views"],"description":"CDS Hierarchy — parent-child tree structure. Key topics: Hierarchies define parent-child relationships for tree structures. Used in Analytical Queries for drill","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Hierarchies define parent-child relationships for tree structures ◆ Used in Analytical Queries for drill-down / roll-up ◆ Key attributes: ◆ Requires: entity with ParentChild association ◆ The source table needs: NodeID, ParentID, and a hirearchy | CDS Source Code ","detailsText":"┌────────────────────┬──────────────────────────────────────┐ │ Attribute │ Description │ ├────────────────────┼──────────────────────────────────────┤ │ @Hierarchy.level │ Node level (root = 1) │ │ ParentChild │ Association to parent node │ │ PARENT │ Parent field in the source table │ │ ORPHANS │ How to handle broken links │ │ MULTIPLE_PARENTS │ Allow multiple parents? │ │ SIBLING_ORDER │ Order among siblings │ │ CARDINALITY │ Node cardinality │ └────────────────────┴──────────────────────────────────────┘ association pointing to itself NOTE: This example uses a PRACTICE-ONLY pattern since /DMO/ doesn't have hierarchy data. The agency table is used with a self-association to demonstrate the concept. In production, use actual hierarchy tables (like ORGUNIT, PROFIT_CTR, etc.)"},{"title":"CDS JSON & XML Functions — Data serialization and transformation","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_JSON_XML","tags":["cds-views"],"description":"CDS JSON & XML Functions — Data serialization and transformation. Key topics: CDS provides built-in functions to serialize entity data into JSON. `with column f","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ CDS provides built-in functions to serialize entity data into JSON ◆ `with column format json` in the SELECT list serialises a column ◆ `with column format xml` serialises a column value as XML — used ◆ `JSON_VALUE( source_column, '$.path' )` extracts a scalar value ◆ `XMLTABLE` inside AMDP transforms XML documents into relational ◆ CDS views can consume JSON/XML via association to custom entities ◆ Semantic annotations like `@Semantics.json.enabled: true` flag | CDS Source Code ","detailsText":"or XML format directly within the view definition. value as JSON — useful for storing complex data in a single field. for backward-compatible integration with older SOAP services. from a JSON string; `JSON_TABLE` (via AMDP) expands JSON arrays into tabular form. rows (requires HANA XML functions). or table functions that handle the parsing logic in ABAP/AMDP. CDS elements for JSON serialization in OData V4 responses. COMPARISON: JSON vs XML in CDS Aspect | JSON Function | XML Function --------------------------------------------------------------------------------------------------------- Serialize to format | `with column format json` | `with column format xml` OData V4 support | Native (JSON as default) | Legacy (SOAP / OData V2) Parse / extract | `JSON_VALUE` expression | `XMLTABLE` in AMDP Array expansion | JSON_TABLE in HANA AMDP | XMLTABLE in HANA AMDP Annotation | @Semantics.json.enabled | @Semantics.xml.enabled Integration use | REST / Fiori / Node.js | SOAP / PI / Legacy ECC Performance | Fast (native HANA JSON) | Moderate (XPath parsing)"},{"title":"CDS Projection Views & Provider Contracts —","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_PROJECTION_VIEWS","tags":["cds-views"],"description":"CDS Projection Views & Provider Contracts —. Key topics: define projection view (or define root view entity as projection. The provider contract clause (availab","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ define projection view (or define root view entity as projection ◆ The provider contract clause (available since ABAP kernel 7.83) ◆ provider contract transactional_query is used for transactional ◆ provider contract transactional_interface defines a projection ◆ provider contract analytical_query creates a V3 analytical ◆ Projection views do NOT create a new DDIC artifact; they are ◆ root vs non-root: define root view entity marks the projection ◆ Release contracts (@AbapCatalog.interface) can be applied to | CDS Source Code ","detailsText":"on) creates a projection of an existing CDS view entity — it does not define new associations or logic, only selects and exposes elements from the underlying source. declares the semantic contract of the projection, determining which OData / InA / RAP consumers are allowed to access it. Fiori UIs built with RAP — these projections are exposed via OData services and are typically root views in a business object. that serves as the interface of a RAP business object — it is consumed by other RAP BOs or by service bindings and must follow strict interface release contracts. projection consumed by SAP Analytics Cloud / InA protocol — no direct SQL reading is allowed (only InA-based tools). pure CDS runtime objects. They cannot define new associations, but existing associations from the source view are visible. as a root node (for transactional scenarios), while a non-root projection delegates the root definition to the source. projection views to govern API stability, ensuring consumers are not broken by internal changes. COMPARISON TABLE: Provider Contracts Feature | transactional_query | transactional_interface | analytical_query ------------------------|-----------------------|-------------------------|-------------------------- Primary use case | Fiori / RAP UI | RAP BO interface layer | Analytics / SAC OData exposure | Yes | Yes (via service binding)| No (InA protocol only) Direct SQL access | Yes | Yes | No (InA only) Root view | Usually root | Usually non-root | N/A Association propagation | From source | From source | From source New associations | No | No | No Release contract | @AbapCatalog.interface| @AbapCatalog.interface | @AbapCatalog.interface SAP Analytics Cloud | No | No | Yes RAP BO consumption | Yes (draft-enabled) | Yes (interface) | No Kernel version | 7.83+ | 7.83+ | 7.83+ SOURCE CODE: Transactional Query Projection (Fiori / RAP)"},{"title":"aware filtering","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_SESSION_VAR","tags":["cds-views"],"description":"Using session variables for context-aware filtering. Key topics: Session variables provide runtime context without ABAP parameters. Evaluated at query execution","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Session variables provide runtime context without ABAP parameters ◆ Evaluated at query execution time based on the ABAP session ◆ Use $session. prefix — distinct from :parameter notation ◆ @Semantics annotations are required on all fields to enable | CDS Source Code ","detailsText":"downstream consumption (OData, Analytics, Fiori) AVAILABLE SESSION VARIABLES (6 total): $session.system_date → Current application server date (DATS) $session.user → Current ABAP user (SY-UNAME) $session.client → Current client (SY-MANDT) $session.system_language → Logon language (SY-LANGU) $session.user_date → User's date according to user profile $session.user_timezone → User's time zone from user profile USE CASES: $session.system_date → Show only past/current records based on today $session.user → Restrict data to user's own created records $session.client → Multi-client filtering (rarely needed — implicit) $session.system_language → Language-dependent text retrieval"},{"title":"CDS Table Entities — Defining HANA database tables natively","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_TABLE_ENTITIES","tags":["cds-views"],"description":"CDS Table Entities — Defining HANA database tables natively. Key topics: define table entity is a new CDS DDL statement introduced in. Because the table is defi","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ define table entity is a new CDS DDL statement introduced in ◆ Because the table is defined purely in CDS, the runtime object ◆ Annotations control every aspect: @EndUserText.label provides ◆ Key fields, client handling, data elements, and built-in types ◆ @Semantics annotations for amount, quantity, currency, and ◆ Activation of a define table entity directly generates or | CDS Source Code ","detailsText":"S/4HANA 2025 that creates a HANA database table directly from CDS source — no separate ABAP Dictionary (DDIC) table artifact is required as an intermediary. IS the HANA table; there is no DDIC table shell to maintain, reducing double-maintenance and transport complexity. the table description, @AbapCatalog.search.help attaches a search help, and @AbapCatalog.tableCategory can specify #TRANSPARENT or #CLUSTER semantics where relevant. are all supported; the client field (usually client = client; or using @AbapCatalog.clientDependent) mimics DDIC client behavior without a separate MANDT column definition. unit of measure work identically to CDS views, enabling the same analytical and transactional metadata natively on the table entity. updates the HANA table in the database; there is no separate activation of a DDIC table followed by a CDS view activation. Transport is handled via the CDS transport layer only. COMPARISON: Table Entity vs Traditional ABAP Dictionary Table Feature | define table entity | Traditional DDIC Table ---------------------------|----------------------------|--------------------------- Artifact type | CDS source (.asddls) | DDIC table (.tab) Database object | Direct HANA table | Buffered via DDIC layer Separate DDIC step? | No | Yes — maintain table in SE11 Transport object | CDS transport (DDL) | DDIC transport (R3TR TABL) Annotation support | Full CDS annotations | Only DDIC field labels @Semantics.amount | Yes | No (must be defined in view) Client handling | @AbapCatalog.clientDependent| MANDT field + technical settings Search help attachment | @AbapCatalog.search.help | SE11 search help assignment Activation speed | Single step (CDS → HANA) | Two steps (DDIC + DB) RAP compatibility | Native (CDS-managed) | Requires CDS view wrapper SOURCE CODE: Custom Audit Log Table Entity"},{"title":"dependent descriptions using @ObjectModel.text.association","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_TEXT_ASSOC","tags":["associations"],"description":"Text Associations — Language-dependent descriptions using @ObjectModel.text.association. Key topics: Text associations follow the _Text naming convention (e.g.,","sections":["Key Learning Points","CDS Source Code"],"sectionsText":"Key Learning Points ◆ Text associations follow the _Text naming convention (e.g., _Text, _DescriptionText) ◆ A text provider view (like I_CurrencyText) exposes language key (spras / language) ◆ The annotation @ObjectModel.text.association: '_Text' on the consumer CDS view ◆ Within the text provider, the text field is flagged with @Semantics.text: true ◆ When the consumer view is exposed, the description appears automatically as ◆ Only the first text element of the provider (based on language priority) is used; | CDS Source Code ","detailsText":"and return language-dependent text data alongside the main entity. and one or more text fields; it acts as the text source for the association. tells the OData runtime to expose the description as a structured annotation. to mark which field carries the actual description text. a property in the OData metadata — the UI does not need to resolve the association. additional text fields are ignored for the @ObjectModel.text.association contract. COMPARISON: Text Association vs Direct Join to Text Table Aspect | Text Association (@ObjectModel.text.association) -------------------------------------------------------------------------- Join syntax | None — implicit via annotation Multiple languages | Automatic — language context resolved at runtime OData exposure | Single property in metadata (auto) Code pushdown | Yes (fully database) Coupling to provider | Decoupled — swap provider without changing consumers Use case | Standard multilingual descriptions (currency, material, etc.) -------------------------------------------------------------------------- Aspect | Direct Join to Text Table (manual _Text join) -------------------------------------------------------------------------- Join syntax | Explicit LEFT OUTER JOIN with language filter Multiple languages | Requires explicit WHERE spras = sy-langu OData exposure | Separate navigation property Code pushdown | Yes (fully database) Coupling to provider | Tight — consumer depends on text table structure Use case | Custom joins or when annotation model cannot be used CDS — Text Provider View (currency text) /* CDS — Consumer View using Text Association"},{"title":"computed fields without database storage","phase":9,"phaseName":"Advanced Data Modeling","category":"Advanced Data Modeling","url":"docs.html#ZPRAC_CDS_VIRTUAL_ELEM","tags":["cds-views"],"description":"Virtual Elements — Runtime-computed fields without database storage. Key topics: Virtual elements are declared with the `virtual` keyword in front of the. The a","sections":["Key Learning Points"],"sectionsText":"Key Learning Points ◆ Virtual elements are declared with the `virtual` keyword in front of the ◆ The annotation @ObjectModel.virtualElementCalculatedBy: 'ABAP:ZCL_...' ◆ The exit class must implement interface IF_SADL_EXIT_CALC_ELEMENT_READ ◆ Method CALCULATE( ) computes values for the given element(s); the framework ◆ Method GET_CALCULATION_INFO( ) provides metadata about which elements ◆ Virtual elements are read-only in OData context — they cannot be written back. ◆ Virtual elements are supported in RAP projection (C_*) views but NOT in","detailsText":"element name inside a CDS projection view. links the virtual element to an ABAP exit class responsible for computing it. to receive the runtime callback. supplies the original data via IO_REQUEST->GET_VALUES( ). the calculator requires from the database. basic CDS views (define view) — only in projection views. PERFORMANCE NOTE Virtual elements BREAK code pushdown. The ABAP-infrastructure fetches all other fields from the database first, then invokes the CALCULATE method in the ABAP layer for EACH row returned. This introduces a round-trip per row group and prevents the database from optimizing the full query. Use virtual elements sparingly — prefer CDS expressions, built-in functions, or table functions whenever the logic can be expressed declaratively in SQL. CDS — Projection View with Virtual Element /* virtual — computed at runtime by ZCL_PRAC_TRAVEL_CALC_ELEMENT */ /* ABAP Class — Virtual Element Calculator Implementation"},{"title":"CDS Study Plan — 6-Week Roadmap","phase":0,"phaseName":"Study Plan","category":"Study Plan","url":"docs.html#ZPRAC_STUDY_PLAN","tags":["study-plan"],"description":"A structured 6-week study plan covering all 64 CDS artifacts across 12 phases, with hourly breakdowns, weekly objectives, and a visual timeline.","sections":["Overview & Timeline","Week 1 — Foundations","Week 2 — Relationships & Grouping","Week 3 — Functions & VDM","Week 4 — Fiori, OData & RAP","Week 5 — Advanced Modeling & Analytics","Week 6 — Enterprise Features","Beyond the Plan"],"sectionsText":"Overview & Timeline <div class=\"text-slate-600 dark:text-slate-400 text-sm leading-relaxed\"><p class=\"mb-4\">This study plan organises <strong>64 CDS artifacts</strong> across <strong>12 learning phases</strong> into a <strong>6-week (~33 hour)</strong> curriculum. Each week bundles related phases so concepts build naturally on one another.</p><div class=\"flex flex-wrap gap-3 mb-4\"><div class=\"flex items-center gap-2 text-xs bg-slate-100 dark:bg-slate-800 rounded-lg px-3 py-2\"><span class=\"font-semibold text-brand-500\">64</span><span class=\"text-slate-500 dark:text-slate-400\">Artifacts</span></div><div class=\"flex items-center gap-2 text-xs bg-slate-100 dark:bg-slate-800 rounded-lg px-3 py-2\"><span class=\"font-semibold text-brand-500\">12</span><span class=\"text-slate-500 dark:text-slate-400\">Phases</span></div><div class=\"flex items-center gap-2 text-xs bg-slate-100 dark:bg-slate-800 rounded-lg px-3 py-2\"><span class=\"font-semibold text-brand-500\">~33h</span><span class=\"text-slate-500 dark:text-slate-400\">Total Duration</span></div><div class=\"flex items-center gap-2 text-xs bg-slate-100 dark:bg-slate-800 rounded-lg px-3 py-2\"><span class=\"font-semibold text-brand-500\">6</span><span class=\"text-slate-500 dark:text-slate-400\">Weeks</span></div></div><div class=\"timeline-hbar\"><div class=\"timeline-segment w1\"><div class=\"week-label\">W1</div><div class=\"phase-label\">Phases 1-2</div><div class=\"phase-hours\">6h</div></div><div class=\"timeline-segment w2\"><div class=\"week-label\">W2</div><div class=\"phase-label\">Phases 3-4</div><div class=\"phase-hours\">6h</div></div><div class=\"timeline-segment w3\"><div class=\"week-label\">W3</div><div class=\"phase-label\">Phases 5-6</div><div class=\"phase-hours\">5h</div></div><div class=\"timeline-segment w4\"><div class=\"week-label\">W4</div><div class=\"phase-label\">Phases 7-8</div><div class=\"phase-hours\">6h</div></div><div class=\"timeline-segment w5\"><div class=\"week-label\">W5</div><div class=\"phase-label\">Phases 9-10</div><div class=\"phase-hours\">6h</div></div><div class=\"timeline-segment w6\"><div class=\"week-label\">W6</div><div class=\"phase-label\">Phases 11-12</div><div class=\"phase-hours\">4h</div></div></div><p class=\"mb-3 font-semibold text-slate-700 dark:text-slate-300\">Prerequisites</p><ul class=\"list-disc pl-5 mb-3 space-y-1\"><li>Basic ABAP syntax (data types, internal tables, classes)</li><li>SQL fundamentals (SELECT, JOIN, WHERE, GROUP BY)</li><li>SAP GUI / ADT (ABAP Development Tools) familiarity</li></ul><p class=\"mb-3 font-semibold text-slate-700 dark:text-slate-300\">How to use</p><ul class=\"list-disc pl-5 space-y-1\"><li>Each week has ~4–6 hours of material — comfortable for one hour per day</li><li>Open each artifact in the docs panel, read key learning points, then study the CDS source code</li><li>Practice by modifying the examples in your own SAP S/4HANA or BTP ABAP environment</li></ul></div> | Week 1 — Foundations <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#1e40af\">1</span><span class=\"study-week-title\">Week 1 — Foundations</span><span class=\"study-week-hours\">~6 hours</span></div><div class=\"study-week-phases\"><span>Phase 1: Fundamentals</span><span>Phase 2: Parameters</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> CDS Intro, View Entity Syntax, Simple View, View on View, Data Manipulation, Type Casting, Input Parameters, Default/Constant/Variable Parameters</div><div class=\"study-week-goal\"><strong>Goal:</strong> Understand the CDS view syntax, create simple views, work with parameters.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Write a view that joins transparent tables and accepts a date range parameter</div></div> | Week 2 — Relationships & Grouping <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#4338ca\">2</span><span class=\"study-week-title\">Week 2 — Relationships &amp; Grouping</span><span class=\"study-week-hours\">~6 hours</span></div><div class=\"study-week-phases\"><span>Phase 3: Joins &amp; Associations</span><span>Phase 4: Aggregation &amp; Subqueries</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> INNER, LEFT, RIGHT, CROSS JOIN, Association, Path Expressions, GROUP BY, HAVING, EXISTS, UNION</div><div class=\"study-week-goal\"><strong>Goal:</strong> Master join types, understand associations vs JOINs, write aggregate queries.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Model an association between header and item views; write a join query with aggregation</div></div> | Week 3 — Functions & VDM <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#6d28d9\">3</span><span class=\"study-week-title\">Week 3 — Functions &amp; VDM</span><span class=\"study-week-hours\">~5 hours</span></div><div class=\"study-week-phases\"><span>Phase 5: Built-in Functions</span><span>Phase 6: VDM</span><span>Phase 9 (partial)</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> String &amp; Date Functions, COALESCE, Currency Conversion, Private/Basic/Composite/Consumption Views, Client Handling, Session Variables</div><div class=\"study-week-goal\"><strong>Goal:</strong> Use built-in functions, apply VDM layering, handle client and session context.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Build a 4-layer VDM stack (Private → Basic → Composite → Consumption) with currency conversion</div></div> | Week 4 — Fiori, OData & RAP <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#be185d\">4</span><span class=\"study-week-title\">Week 4 — Fiori, OData &amp; RAP</span><span class=\"study-week-hours\">~6 hours</span></div><div class=\"study-week-phases\"><span>Phase 7: Fiori &amp; OData</span><span>Phase 8: RAP &amp; Extensibility</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> Metadata Extension, UI Annotations, Value Help, Search, OData Draft, Service Expose, Composition, Object Model, RAP Behavior, Extensibility, View Extension, Numbering</div><div class=\"study-week-goal\"><strong>Goal:</strong> Annotate views for Fiori, expose OData services, define RAP behavior with early/late numbering.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Create a full RAP stack: CDS → Behavior → Service → UI annotations → Draft-enabled Fiori app</div></div> | Week 5 — Advanced Modeling & Analytics <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#c2410c\">5</span><span class=\"study-week-title\">Week 5 — Advanced Modeling &amp; Analytics</span><span class=\"study-week-hours\">~6 hours</span></div><div class=\"study-week-phases\"><span>Phase 9: Advanced Data Modeling</span><span>Phase 10: Analytics &amp; Security</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> Hierarchy, Text Association, Virtual Elements, Custom/Abstract Entities, Table Entities, Projection Views, JSON/XML, DCL, Analytical CDS &amp; V3, Release Contracts</div><div class=\"study-week-goal\"><strong>Goal:</strong> Model complex CDS patterns, secure data with DCL, build analytical star schemas.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Design an analytical CDS view with cube/query; secure it with instance-based DCL</div></div> | Week 6 — Enterprise Features <div class=\"study-week-card\"><div class=\"study-week-header\"><span class=\"study-week-badge\" style=\"background:#047857\">6</span><span class=\"study-week-title\">Week 6 — Enterprise Features</span><span class=\"study-week-hours\">~4 hours</span></div><div class=\"study-week-phases\"><span>Phase 11: Table Functions &amp; AMDP</span><span>Phase 12: Quality &amp; Enterprise</span></div><div class=\"study-week-artifacts\"><strong>Artifacts:</strong> Simple/Parameterized/Currency/Advanced TF, Simple/Dynamic AMDP, Performance, Unit Testing, RAP Eventing, Cloud Core</div><div class=\"study-week-goal\"><strong>Goal:</strong> Implement table functions, write AMDPs, optimise performance, test and deploy cloud-ready CDS.</div><div class=\"study-milestone\"><span class=\"icon\">✔️</span> <strong>Milestone:</strong> Create an AMDP-based table function, write ABAP unit tests with CDS test doubles, apply performance rules</div></div> | Beyond the Plan <div class=\"text-slate-600 dark:text-slate-400 text-sm leading-relaxed\"><p class=\"mb-3\">These advanced topics extend beyond the 64 core artifacts. Refer to SAP Help Portal and SAP Community for deep dives.</p><table class=\"w-full text-xs border-collapse\"><thead><tr class=\"border-b border-slate-200 dark:border-slate-700\"><th class=\"text-left py-1.5 pr-2 font-semibold text-slate-700 dark:text-slate-300\">Topic</th><th class=\"text-left py-1.5 font-semibold text-slate-700 dark:text-slate-300\">Description</th></tr></thead><tbody><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">CDS-based BW Bridge / ODP</td><td class=\"py-1.5\">Extract CDS data into SAP BW using ODP context and extraction views</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">Fiori Elements Advanced UX</td><td class=\"py-1.5\">Custom sections, multi-edit tables, guided procedures, and flexible column layouts</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">Multi-tenant DCL</td><td class=\"py-1.5\">Field-level vs instance-level authorization in cloud and on-premise multi-tenant systems</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">Advanced RAP Determinations</td><td class=\"py-1.5\">Side-effects, dynamic actions, feature control, and internal vs external numbering</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">CDS with External OData/RFC</td><td class=\"py-1.5\">Consuming CDS views via RAP outbound service or OData client proxy</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">CDS Entity Manipulation Language (EML)</td><td class=\"py-1.5\">Programmatic MODIFY ENTITIES / READ ENTITIES for transactional operations</td></tr><tr class=\"border-b border-slate-100 dark:border-slate-800\"><td class=\"py-1.5 pr-2\">SAP Cloud Platform Transport</td><td class=\"py-1.5\">gCTS / abapGit for CDS transport across cloud landscapes</td></tr><tr><td class=\"py-1.5 pr-2\">CDS-based Custom Fields &amp; Logic</td><td class=\"py-1.5\">Key User Extensibility with custom CDS fields and logic via S/4HANA Cloud</td></tr></tbody></table></div>","detailsText":""}];
